const PROVISION_INDEX=[{"id": "s1-1", "num": "§1.1", "name": "Right of Access to Courts", "text": "Every person may seek legal remedy for any rights violation — a self-executing right that courts may not make meaninglessly expensive through procedural costs. If the Legislature fails to fund legal aid, courts appoint counsel at public expense until a statutory framework exists — the self-executing"}, {"id": "s1-2", "num": "§1.2", "name": "Individual Sovereignty Floor", "text": "Every person holds an individual sovereignty that government authority may limit only as this Constitution permits — and may never eliminate. No official, institution, or emergency suspends this floor. The State may deprive a person of life only as the lawful consequence of a sentence imposed by a c"}, {"id": "s1-3", "num": "§1.3", "name": "Prohibition of Torture and Cruel Treatment", "text": "Absolute prohibition on torture, cruel treatment, and degrading punishment. No exception exists — not for national security, not for emergency, not for military operations. One of six permanently unamendable provisions under §15.3.a."}, {"id": "s1-4", "num": "§1.4", "name": "Prohibition of Slavery and Forced Labor", "text": "Slavery, forced labor, debt bondage, and compelled service are prohibited absolutely and in all forms. The prohibition extends to all persons within the Republic's jurisdiction, not merely to citizens. Jury service required under §4.5 and lawful sentences of community service imposed by a court do n"}, {"id": "s1-5", "num": "§1.5", "name": "Freedom of Expression", "text": "No branch, agency, official, or instrumentality of the Republic or any State may abridge the freedom of speech, press, or assembly in any medium — physical or digital."}, {"id": "s1-5-a", "num": "§1.5.a", "name": "Censorship by Proxy", "text": "Government actors may not pressure, incentivize, or coerce private platforms or institutions to suppress speech on their behalf. Such an act constitutes the same constitutional violation as direct censorship. This prohibition applies equally to digital and physical media. Government may not impose v"}, {"id": "s1-6", "num": "§1.6", "name": "Freedom of Thought, Conscience, and Religion", "text": "Every person has the right to hold, practice, change, or decline any belief and to manifest it through worship, observance, practice, and teaching. No person may be compelled to participate in any religious observance contrary to their beliefs. Free exercise does not authorize harm to others and cre"}, {"id": "s1-6-a", "num": "§1.6.a", "name": "Separation of Church and State", "text": "No religion may be established by law, and public funds directed to religious organizations must comply with the equality requirements of §1.9. The separation of church and state is structural, not merely preferential."}, {"id": "s1-7", "num": "§1.7", "name": "Freedom of Association", "text": "Every person has the right to freely associate with others for any lawful purpose — including political parties, trade unions, civic organizations, and professional associations. The State may not compel membership as a condition of employment or civic participation, nor prohibit any association sol"}, {"id": "s1-8", "num": "§1.8", "name": "Right to Petition", "text": "Every Inhabitant has the right to petition any branch of government on any matter of public or personal concern. All petitions must receive a formal response within a Legislature-defined period. The subject and status of petitions are published to the National Record System; petitioner identity is w"}, {"id": "s1-9", "num": "§1.9", "name": "Equality and Non-Discrimination", "text": "Every person is equal before the law. No person may be discriminated against on the basis of the enumerated characteristics. Distinctions based on race, ethnicity, religion, sex, sexual orientation, gender identity, national origin, or disability are presumptively unconstitutional, requiring a compe"}, {"id": "s1-10", "num": "§1.10", "name": "Bodily Autonomy and Digital Privacy", "text": "Every person holds bodily and digital sovereignty against government intrusion. No government actor may compel medical procedures, appropriate personal data, or obtain cryptographic keys without express constitutional authorization."}, {"id": "s1-10-a", "num": "§1.10.a", "name": "Physical Sovereignty", "text": "Every person has the absolute right to refuse any medical procedure or biological sampling. No mandate is permissible under any declared emergency unless the individual provides uncoerced, revocable written consent."}, {"id": "s1-10-b", "num": "§1.10.b", "name": "Data Ownership", "text": "Individuals own their personal data, likeness, and biometric information. Data collected by any government actor is subject to strict necessity limits — it may not be retained beyond the purpose for which it was collected, shared with third parties without..."}, {"id": "s1-10-c", "num": "§1.10.c", "name": "Encryption Protection", "text": "Cryptographic keys are private property. No court or agency may compel their disclosure without a specific judicial warrant meeting the standards of §1.11.a — identifying the particular key sought and the purpose for which it is sought, issued by a judicial officer on an individualized finding of ne"}, {"id": "s1-11", "num": "§1.11", "name": "Inviolability of the Home and Property Rights", "text": "Every person's home is inviolable against government access without judicial warrant. Private property may not be taken except by absolute public necessity under the conditions of §1.11.b. The definition of \"home\" for purposes of this provision is established in §1.11.a."}, {"id": "s1-11-a", "num": "§1.11.a", "name": "Home and Digital Privacy", "text": "'Home' extends to all physical residences and all digital spaces secured by private cryptographic keys. Access requires a warrant specifying the precise data target or physical space, verified on the NRS before execution. General warrants — broad or unspecified authorizations — are absolutely prohib"}, {"id": "s1-11-b", "num": "§1.11.b", "name": "Eminent Domain", "text": "Seizure of private property requires proof of absolute public necessity, payment of 150% of fair market value, and NRS publication. Private-to-private transfer via eminent domain — using government condemnation to benefit another private party — is constitutionally prohibited."}, {"id": "s1-12", "num": "§1.12", "name": "Self-Defense and the Right to Bear Arms", "text": "The right to keep and bear arms for personal defense and hunting must not be infringed. The scope and limits of this right are established in §1.12.a through §1.12.c."}, {"id": "s1-12-a", "num": "§1.12.a", "name": "Right to Bear Arms", "text": "The right to keep and bear arms is a personal right held by each individual. It is not a collective right conditional on militia service or membership, and does not require any governmental authorization for keeping arms in the home."}, {"id": "s1-12-b", "num": "§1.12.b", "name": "State Licensing Latitude", "text": "States may establish licensing and safety training requirements as a condition of carrying or possessing firearms. States may regulate the exercise of the right but may not use regulation as a prohibition by another name."}, {"id": "s1-12-c", "num": "§1.12.c", "name": "Non-Prohibition Principle", "text": "No State requirement may function as an effective prohibition on keeping or bearing arms. A requirement is an effective prohibition if it imposes costs, delays, or conditions that make lawful ownership practically inaccessible to ordinary citizens. The burden of proof lies with the State to demonstr"}, {"id": "s1-13", "num": "§1.13", "name": "Freedom of Movement and Labor", "text": "All Inhabitants have the right to travel and reside anywhere within the Republic. State professional licensing requirements may not create barriers to labor mobility; licenses issued under State law are recognized throughout the Republic. Every person has the right to form and join trade unions and "}, {"id": "s1-14", "num": "§1.14", "name": "Detention and Habeas Corpus Rights", "text": "Any person taken into custody by the State holds the rights established in this section. These rights are self-executing and may not be suspended by statute or executive order."}, {"id": "s1-14-a", "num": "§1.14.a", "name": "First Appearance", "text": "Any person taken into custody must appear before a judicial officer within 72 hours of arrest. At the First Appearance, the judge must determine whether custody is lawful and whether conditions of release are appropriate."}, {"id": "s1-14-b", "num": "§1.14.b", "name": "Habeas Corpus Response Deadline", "text": "A court receiving a habeas corpus petition must rule within 48 hours of filing. No procedural rule may extend this deadline. A court that fails to rule within 48 hours is deemed to have found the detention unlawful — the detained person must be released or brought before a judicial officer immediate"}, {"id": "s1-14-c", "num": "§1.14.c", "name": "Habeas Corpus", "text": "Any person detained by the State has the absolute right to challenge the lawfulness of their confinement before a judge at any time. The right cannot be suspended by emergency declaration — it appears in §1.26.b's list of absolutely non-derogable rights."}, {"id": "s1-15", "num": "§1.15", "name": "Rights of the Accused", "text": "Every person accused of a crime or subject to criminal proceedings holds the rights established in this section from the moment of accusation through final disposition."}, {"id": "s1-15-a", "num": "§1.15.a", "name": "Right to Counsel", "text": "Any person accused of a crime or subject to detention has the right to retain and consult with a lawyer before questioning. If they cannot afford counsel, the Republic provides it. The right attaches from the moment of accusation or detention, not from formal charging."}, {"id": "s1-15-b", "num": "§1.15.b", "name": "Caseload Guarantee", "text": "The Legislature must establish maximum caseload limits for publicly funded defense — ensuring that the right to counsel means genuine preparation, not nominal presence. Public defenders must be resourced equivalently to prosecutorial offices handling comparable cases."}, {"id": "s1-15-c", "num": "§1.15.c", "name": "Right to Be Informed of Charges", "text": "Any person detained or accused must be informed promptly, in plain language they understand, of the specific grounds for their detention and the charges being considered. Detention without meaningful explanation of its basis is unconstitutional from its first moment."}, {"id": "s1-15-d", "num": "§1.15.d", "name": "Right to Full Disclosure", "text": "Any accused person has the right to full disclosure of all State evidence — including evidence the prosecution does not intend to use — before trial. Any withholding of exculpatory evidence is a constitutional violation, not a procedural irregularity."}, {"id": "s1-16", "num": "§1.16", "name": "Fair Trial Rights", "text": "Every person subject to criminal proceedings has the right to a fair and timely trial. These rights may not be waived by prosecutorial pressure, plea incentive, or judicial scheduling convenience."}, {"id": "s1-16-a", "num": "§1.16.a", "name": "Speedy Trial Principle", "text": "Every accused person has the right to trial without unreasonable delay. Delay caused by the State is not a neutral fact — prolonged pre-trial detention is itself a punishment imposed without verdict. What constitutes unreasonable delay is defined by the Legislature in statute, subject to judicial re"}, {"id": "s1-16-b", "num": "§1.16.b", "name": "Bail Proportionality", "text": "Pre-trial detention may only be ordered where the court makes a specific, individualized finding that the accused poses a genuine flight risk or documented danger to an identifiable person. Financial inability to post bail does not justify detention — bail conditions must be proportionate to what th"}, {"id": "s1-16-c", "num": "§1.16.c", "name": "Protection from Trial Penalties", "text": "The right to trial may not be penalized. A defendant who exercises their right to trial may not receive a harsher sentence than they would have received by entering a guilty plea for the same offense. Sentencing 'trial penalties' are constitutionally prohibited."}, {"id": "s1-16-d", "num": "§1.16.d", "name": "Source Code Right", "text": "Any accused person has the right to inspect, challenge, and rebut any algorithm, automated system, statistical model, or raw dataset used as evidence or to generate a score influencing their case. Technology-opaque evidence against which no defense can be mounted is constitutionally inadmissible."}, {"id": "s1-17", "num": "§1.17", "name": "Right to Silence", "text": "No person may be compelled to testify against themselves or to produce self-incriminating evidence. The right of silence is complete — silence may not be commented upon or used to draw adverse inferences. Consistent with §1.10.c, this extends to cryptographic keys."}, {"id": "s1-18", "num": "§1.18", "name": "Right to a Public Trial", "text": "Every accused person has the right to a public trial before a judge and, in criminal matters, a jury of peers. Secret or closed proceedings are constitutionally prohibited except for the minimal portion where a specific witness's safety requires it — and even then the verdict must be public. Also pe"}, {"id": "s1-19", "num": "§1.19", "name": "Criminal Law Limits", "text": "The criminal law may not be applied retroactively or used to punish a person more than once for the same conduct. These prohibitions apply equally to the federal government and to every State."}, {"id": "s1-19-a", "num": "§1.19.a", "name": "No Retroactive Criminal Laws", "text": "No person may be convicted of an act that was not defined as a criminal offense at the time it was committed. No sentence may exceed the maximum available at the time of the offense. The prohibition on retroactive criminal law is absolute and permanently unamendable."}, {"id": "s1-19-b", "num": "§1.19.b", "name": "Double Jeopardy", "text": "No person may be tried or punished more than once for the same offense arising from the same factual events. Acquittal is final. This applies across all levels of the Republic's court system — a State court acquittal cannot be retried in a federal court on the same facts."}, {"id": "s1-20", "num": "§1.20", "name": "Right to Democratic Participation", "text": "No government action may make voting materially more difficult for any eligible citizen. This covers not only formal disenfranchisement but practical barriers: polling place closures, identification requirements that function as wealth or document-access tests, registration obstacles designed to sup"}, {"id": "s1-21", "num": "§1.21", "name": "Right to Marry and Found a Family", "text": "The right to marry or form a legally recognized partnership belongs to any two consenting adults regardless of sex, gender, or sexual orientation. The Republic must recognize such partnerships for all legal purposes. The Legislature and States may not create hierarchies of partnership recognition ba"}, {"id": "s1-22", "num": "§1.22", "name": "Rights of Children", "text": "Every child has the right to protection from exploitation, abuse, and neglect. In all State actions affecting minors, the welfare and best interests of the child are the primary consideration — not merely one factor to be weighed."}, {"id": "s1-23", "num": "§1.23", "name": "Environmental Accountability", "text": "The federal government holds an enforceable constitutional obligation to protect communities from government-caused environmental harm and to maintain the long-term ecological integrity of the Republic's natural environment. Both obligations are subject to annual Inspectorate reporting under §8.1."}, {"id": "s1-23-a", "num": "§1.23.a", "name": "Government Non-Harm", "text": "No government authority may knowingly expose any community of Inhabitants to environmental hazards without full disclosure, meaningful consultation, and proportionate mitigation. The Government Non-Harm principle makes environmental poisoning of communities a constitutional violation, not merely a p"}, {"id": "s1-23-b", "num": "§1.23.b", "name": "Environmental Stewardship", "text": "The long-term stewardship of the Republic's natural environment is a constitutional obligation of the federal government — not aspirational language. It creates an enforceable duty to maintain ecological integrity that the Inspectorates are mandated to report on annually."}, {"id": "s1-24", "num": "§1.24", "name": "Education and Literacy Rights", "text": "Every child holds a constitutional right to education adequate to participate fully in civic life. The Republic's obligation under this section is both corrective — addressing wealth-based inequality in educational opportunity — and foundational — ensuring public education equips every student to me"}, {"id": "s1-24-a", "num": "§1.24.a", "name": "Federal Education Assistance", "text": "The Republic must provide adequate education assistance to States and Territories so that no child's educational opportunity is determined primarily by the wealth of their territory. Federal assistance must address the gap between what a jurisdiction can fund locally and what the constitutional lite"}, {"id": "s1-24-b", "num": "§1.24.b", "name": "Constitutional Literacy", "text": "Public education must equip every student to understand the structure, rights, and civic obligations established by this constitution. This is a substantive floor — not a test requirement, but an educational outcome. The constitutional literacy standard for citizenship naturalization purposes is sep"}, {"id": "s1-24-c", "num": "§1.24.c", "name": "Parental Right", "text": "Parents retain the right to educate children through alternative means — homeschooling, faith-based schools, alternative institutions — provided those alternatives meet the constitutional literacy standard. The Republic may set the floor; it may not mandate the method."}, {"id": "s1-25", "num": "§1.25", "name": "Housing Non-Exclusion", "text": "Housing access is a constitutional right — no government authority may use its powers to exclude persons from housing on discriminatory grounds or to deny housing to those who cannot independently secure it. The non-exclusion principle is established in §1.25.a and the social assistance housing obli"}, {"id": "s1-25-a", "num": "§1.25.a", "name": "Non-Exclusion Principle", "text": "No government authority — federal, State, or local — may use regulatory or land-use powers to exclude any person from access to housing on the basis of any characteristic enumerated in §1.9. Exclusionary zoning designed to keep certain populations out of a community is constitutionally prohibited."}, {"id": "s1-25-b", "num": "§1.25.b", "name": "Social Assistance Housing Obligation", "text": "Housing access for persons who cannot independently secure it is a social assistance obligation under §10.1.b. Housing exclusion is an enforceable constitutional violation."}, {"id": "s1-26", "num": "§1.26", "name": "Emergency Derogation", "text": "No emergency — however severe — suspends the Individual Sovereignty Floor in full. Temporary derogation of certain rights is permitted only under the strict conditions of this section; the rights enumerated in §1.26.b may not be derogated under any circumstances."}, {"id": "s1-26-a", "num": "§1.26.a", "name": "Emergency Derogation — Declaration Requirements", "text": "Emergency derogation of Article I rights requires a precisely structured declaration specifying: the nature of the emergency, which rights are limited, the geographic scope, the duration, and the review mechanism. The specificity requirement prevents open-ended emergency licenses — the government mu"}, {"id": "s1-26-b", "num": "§1.26.b", "name": "Non-Derogable Rights", "text": "These six rights are absolute under any circumstances: the prohibition on torture (§1.3); slavery (§1.4); habeas corpus (§1.14); the right to a public trial (§1.18); no retroactive punishment (§1.19); and non-refoulement (§1.28). No emergency declaration, executive order, or legislative act may dero"}, {"id": "s1-26-c", "num": "§1.26.c", "name": "Inspectorate Continuity", "text": "The three Inspectorates continue to operate with full constitutional authority throughout any emergency — they cannot be suspended or have their mandate reduced by emergency declaration. Accountability infrastructure is precisely most important when emergency powers are active."}, {"id": "s1-26-d", "num": "§1.26.d", "name": "Automatic Expiry and Judicial Review", "text": "Emergency measures lapse automatically at the expiry of the Declaration. Judicial review of any emergency measure is available to any citizen at any time, and courts may rule during the emergency that a specific measure is unconstitutional."}, {"id": "s1-26-e", "num": "§1.26.e", "name": "No Permanent Emergency", "text": "No emergency measure may be made permanent by legislative act. Every emergency measure lapses automatically at the expiry of the Declaration unless re-enacted through the ordinary legislative process. The Legislature may not extend an emergency measure by re-declaration within 60 days of its expiry,"}, {"id": "s1-27", "num": "§1.27", "name": "Associated Community Residents", "text": "Every person residing within any Associated Community operating under a compact with the Republic holds the full protections of Article I, enforceable directly by federal courts regardless of the Associated Community's internal governance structure. No compact provision may limit or qualify any Arti"}, {"id": "s1-28", "num": "§1.28", "name": "Non-Refoulement", "text": "No person within the Republic's jurisdiction may be returned, expelled, or extradited to any territory where they face genuine risk of persecution, torture, or deprivation of life based on race, religion, nationality, political opinion, or group membership. No exception applies for immigration statu"}, {"id": "s1-29", "num": "§1.29", "name": "Medical Autonomy", "text": "Medical decisions belong to the patient and their licensed provider. Government's legitimate role is professional licensing, scope of practice, and safety standards — not directing the content of medical decisions or penalizing their exercise. No government may impose civil or criminal liability on "}, {"id": "s1-30", "num": "§1.30", "name": "Right to Privacy", "text": "Every person holds a right to privacy in their person, home, communications, associations, health, and personal data. The government may abridge this right only on a showing of specific, articulable necessity and only to the minimum extent that necessity requires. The general right governs wherever "}, {"id": "s1-30-a", "num": "§1.30.a", "name": "Searches and Seizures", "text": "No unreasonable search or seizure of person, home, property, communications, or data. Any authorized search must be narrowly scoped, judicially approved before execution, and recorded on the NRS. General warrants — broad or unspecified authorizations — are absolutely prohibited. Digital spaces secur"}, {"id": "s1-30-b", "num": "§1.30.b", "name": "Medical Privacy", "text": "Medical information, health records, genetic data, and bodily condition are private. Government compulsion requires a specific judicial order in active legal proceedings, limited to what those proceedings directly require. Public health law disclosures must be proportionate, time-limited, and NRS-re"}, {"id": "s1-30-c", "num": "§1.30.c", "name": "Communications and Data", "text": "Government collection of private communications or personal data requires specific judicial authorization identifying the person, the data sought, and the collection period. Bulk collection without individual identification is prohibited outright. Private-sector entities cannot be compelled to colle"}, {"id": "s1-30-d", "num": "§1.30.d", "name": "Intelligence Firewall", "text": "All domestic intelligence operations against Republic citizens are prohibited and constitutionally void. Any such order is reported to the NRS by the EI. This prohibition is non-derogable — no emergency, treaty, or statute can suspend it."}, {"id": "s1-30-e", "num": "§1.30.e", "name": "Associational Privacy", "text": "Government mapping of associations — who a person knows, meets, communicates with, or joins — requires the same specific judicial authorization as communications collection under §1.30.c. Bulk mapping of associational activity is prohibited on the same terms as bulk collection. The privacy of associ"}, {"id": "s2-1", "num": "§2.1", "name": "The President — Term and Transfer", "text": "The President holds enumerated executive authority over: military command, foreign affairs, intelligence, treaty negotiation, trade agreements, and domain officer appointments. Presidential authority is enumerated; PM authority is residual. Upon expiration of the presidential term, all authority tra"}, {"id": "s2-1-a", "num": "§2.1.a", "name": "Tier 1 — Immediate Defensive Response", "text": "The President may respond immediately to an active, imminent, or ongoing attack on Republic territory, Republic citizens abroad, or treaty allies without prior legislative authorization. The only presidential power that can be exercised without legislative consent. Strictly bounded: defensive operat"}, {"id": "s2-1-b", "num": "§2.1.b", "name": "Tier 2 — Senate Armed Services Authorization", "text": "Required within 96 hours for any offensive operation or sustained defensive deployment. Simple majority of the Committee following a classified presidential briefing. Covers 30 days. If the full Legislature does not pass a Tier 3 Declaration within 30 days, all operations except immediate territoria"}, {"id": "s2-1-c", "num": "§2.1.c", "name": "Tier 3 — Legislative Declaration of Defense", "text": "The full democratic authorization. 2/3 concurrent majority of both chambers. Must state the §12.1 authorized purpose. Renewable every 180 days — failure to renew terminates all operations and expenditure with no presidential override. Maximum 5 years then mandatory 90-day cessation."}, {"id": "s2-1-d", "num": "§2.1.d", "name": "Funding Lock", "text": "The President has no authority to spend domestic funds. All military expenditure requires PM certification. Tier 1 defensive operations carry an automatic 96-hour Emergency Defense Allocation — self-executing, not subject to PM Fiscal Objection. Beyond 96 hours, PM must certify or uncertified spendi"}, {"id": "s2-1-e", "num": "§2.1.e", "name": "Presidential Intelligence Limits", "text": "The prohibition on domestic intelligence operations against Republic citizens is non-derogable and permanent under §1.30.d. Any order authorizing domestic intelligence operations against Republic citizens is constitutionally void. The EI reports any such order to the NRS."}, {"id": "s2-1-f", "num": "§2.1.f", "name": "Presidential Veto — Scope", "text": "The President may veto only bills that raise a genuine constitutional concern within the security domain: military operations, intelligence, treaty obligations, or border security. A general or speculative security connection is not sufficient. The SC reviews any Presidential veto within 48 hours on"}, {"id": "s2-1-f-i", "num": "§2.1.f.i", "name": "Judicial Review and Override", "text": "Automatic expedited SC review within 48 hours of petition by either Speaker. The Court determines only whether the bill genuinely raises a constitutional concern within the President's defined domain — not whether the President's security judgment is correct. If the bill does not raise a genuine dom"}, {"id": "s2-1-f-ii", "num": "§2.1.f.ii", "name": "Veto Suspension for Repeated Void Vetoes", "text": "If the Supreme Court voids three Presidential vetoes on scope or justification grounds within any 180-day period, the President's veto authority is suspended for the remainder of that period. The Legislative Inspectorate publishes a finding to the NRS upon suspension. Suspension affects only the vet"}, {"id": "s2-1-g", "num": "§2.1.g", "name": "Presidential Clemency", "text": "Presidential clemency is domain-scoped: military law and national security offenses only. Before any grant, the EI publishes a factual background report to the NRS. Clemency may not be granted for: any offense in which the President was a participant, co-conspirator, or direct beneficiary; any offen"}, {"id": "s2-1-h", "num": "§2.1.h", "name": "Dual Executive Conflict Resolution During Active Operations", "text": "Where both executives disagree on whether a military operation falls within the Presidential military domain during active operations, either executive may file a written NRS objection within 6 hours. The executives have 12 hours to resolve the dispute by negotiation. Where no resolution is reached,"}, {"id": "s2-1-i", "num": "§2.1.i", "name": "International Trade Authority", "text": "The President negotiates and concludes trade agreements; PM written concurrence is required where the agreement materially affects the domestic economy. National treatment obligations within Republic territory require PM concurrence, as they directly govern how domestic industry is regulated. Where "}, {"id": "s2-1-j", "num": "§2.1.j", "name": "Presidential Officer Appointments and Removal", "text": "The President nominates the Director of Intelligence, Secretary for Foreign Affairs, and Secretary for Defense. The Senate confirms each nomination by simple majority within a period the Legislature defines by statute. If the Senate has not voted within that period, the President may name an Acting "}, {"id": "s2-2", "num": "§2.2", "name": "The Prime Minister — Domestic Executive Domain", "text": "The PM holds residual executive authority over all functions not enumerated as Presidential. To be eligible, a person must have held citizenship for at least 10 years. The PM answers to the House through the confidence mechanism and does not require presidential confirmation for the exercise of the "}, {"id": "s2-2-a", "num": "§2.2.a", "name": "Domestic Policy Authority", "text": "The Prime Minister holds authority over all domestic policy — healthcare, education, infrastructure, housing, labour, environment, and all domestic regulatory frameworks. This authority is residual: it covers every function not expressly enumerated as Presidential under §2.1."}, {"id": "s2-2-b", "num": "§2.2.b", "name": "Ministerial Appointments", "text": "PM appoints senior domestic officers from candidates whose qualifications have been certified by the JI against criteria established by statute. The registry requirement prevents purely political appointments. Senate confirmation provides a further check. PM removal of appointed officers requires pu"}, {"id": "s2-2-c", "num": "§2.2.c", "name": "PM Fiscal and Budget Authority", "text": "The annual budget originates with the PM and requires House passage. The PM's certification function for military expenditure is the financial check on the President's domain: no military operation runs without PM-certified funds."}, {"id": "s2-2-d", "num": "§2.2.d", "name": "Legislative Review Period", "text": "The PM reviews all enacted legislation and may sign, apply a Fiscal Objection, or apply a Suspensive Veto. Silence within the Legislative Review Period triggers Deemed Enactment — there is no veto by inaction. The Suspensive Veto returns the bill to the Legislature, which may override by 2/3 of both"}, {"id": "s2-2-e", "num": "§2.2.e", "name": "Domestic Emergency Authority", "text": "The PM may declare a domestic emergency in response to natural disaster, public health crisis, or civil infrastructure failure. Strictly bounded: no suspension of Article I rights, 30-day initial period renewable by House approval, all emergency orders published to the NRS within 6 hours. The Presid"}, {"id": "s2-2-f", "num": "§2.2.f", "name": "PM Clemency", "text": "Same procedural structure as Presidential clemency: EI factual report published to NRS before any grant. Self-clemency prohibited under §2.9.b. The PM may not pardon Presidential domain offenses under §2.9.c. Broad amnesty for groups requires legislative action under §2.9.a."}, {"id": "s2-2-g", "num": "§2.2.g", "name": "PM Information Rights", "text": "The PM has a constitutional right to full and timely briefing on all national security matters affecting domestic interests. The President may not withhold information from the PM on grounds of security classification where those matters bear on the PM's domestic responsibilities. The Intelligence F"}, {"id": "s2-2-h", "num": "§2.2.h", "name": "Caretaker PM Framework", "text": "Where the PM is temporarily unable to exercise authority, the most senior confirmed Cabinet Minister by continuous length of service, as certified by the JI, serves as Caretaker PM. The Caretaker PM's authority is limited to maintaining existing policy and emergency functions. Caretaker status expir"}, {"id": "s2-2-i", "num": "§2.2.i", "name": "Duty of Refusal", "text": "Civil servants must refuse and report any order that lacks required PM fund certification, violates any Article I right, or has not been recorded on the National Record System. A civil servant who refuses an unconstitutional order may not be dismissed, demoted, or penalized for that refusal. The EI "}, {"id": "s2-2-j", "num": "§2.2.j", "name": "Civil Service Integrity", "text": "The PM has constitutional responsibility for the integrity of the civil service. Civil service appointments, promotions, and assignments must be made on the basis of merit and qualification, not political affiliation. Civil servants are protected from retaliation for exercising their duty of refusal"}, {"id": "s2-2-k", "num": "§2.2.k", "name": "Domestic Affairs Council", "text": "The PM administers domestic executive functions through the Domestic Affairs Council — the coordinating body of senior Cabinet Ministers responsible for the delivery of social state obligations under §10.1, oversight of devolved Territories, co-management of National Trust lands, and other domestic "}, {"id": "s2-3", "num": "§2.3", "name": "Prime Minister — Accountability and Formation", "text": "The Prime Minister is accountable to the House through the mechanisms of this section. The House's power to remove the PM is matched by its constitutional obligation to maintain a functioning government."}, {"id": "s2-3-a", "num": "§2.3.a", "name": "Constructive Vote of No Confidence", "text": "The House cannot simply vote 'no confidence' and leave a vacuum; it must simultaneously elect a replacement by absolute majority of full seated House membership. Both the removal and successor election occur in the same vote."}, {"id": "s2-3-b", "num": "§2.3.b", "name": "PM Maximum Consecutive Service", "text": "The 8-year maximum — no PM may serve more than 8 consecutive years. After 8 years, the PM must stand down even if the House would re-elect them. The 8-year maximum and the constructive vote operate independently — a PM reaching 8 years is replaced through a House election of a successor."}, {"id": "s2-3-c", "num": "§2.3.c", "name": "PM Formation and Senate Designation", "text": "The House elects the PM by absolute majority of full seated membership within 30 days of any general election. The House may attempt to elect a PM at any time. If the House has not elected a PM within 30 days, the most senior confirmed Cabinet Minister by continuous length of service continues as Ca"}, {"id": "s2-4", "num": "§2.4", "name": "Prime Minister — Legislative Instruments", "text": "The PM holds two instruments for engaging the Legislature on enacted bills: the Suspensive Veto and the Fiscal Objection."}, {"id": "s2-4-a", "num": "§2.4.a", "name": "Suspensive Veto", "text": "The PM may return any bill to the Legislature with a written Statement of Objection specifying the constitutional, fiscal, or operational grounds. The statement is recorded permanently on the NRS. The Legislature may override by 2/3 of both chambers simultaneously. The suspensive veto may not be use"}, {"id": "s2-4-b", "num": "§2.4.b", "name": "Fiscal Objection", "text": "A narrower tool than the Suspensive Veto. The PM may object to legislation on specific solvency grounds: the bill, if enacted, would cause or materially worsen a structural deficit beyond constitutional thresholds. Requires MA assessment within 21 days. House may override by simple majority after re"}, {"id": "s2-4-c", "num": "§2.4.c", "name": "Deemed Enactment", "text": "If the PM neither signs nor objects within the Legislative Review Period, the bill is automatically enacted. Silence is not a veto."}, {"id": "s2-5", "num": "§2.5", "name": "Legislative Review Period", "text": "Both executives hold a concurrent review period following final passage of any bill."}, {"id": "s2-5-a", "num": "§2.5.a", "name": "Legislative Review Period — Duration", "text": "The presidential veto period may not exceed 20 days; the PM objection period may not exceed 45 days. The periods run concurrently from the date of final passage in both chambers. If neither executive acts within their respective period, the bill is deemed enacted. The President and PM may jointly ag"}, {"id": "s2-6", "num": "§2.6", "name": "Presidential Succession", "text": "The President's succession and acting authority framework is established in §2.6.a through §2.6.c."}, {"id": "s2-6-a", "num": "§2.6.a", "name": "Presidential Succession Line", "text": "Full succession activates on Presidential death, resignation, removal, or certified permanent incapacity under §2.6.b. Authority transfers in order: (1) the Senate Speaker; (2) the Senate Deputy Speaker; (3) the most senior member of the Senate Armed Services Committee by years of Senate service. Wh"}, {"id": "s2-6-b", "num": "§2.6.b", "name": "Temporary Acting Presidential Authority", "text": "Where the President is incapacitated and unable to exercise presidential authority, the EI and LI jointly assess capacity within 6 hours. If both Inspectorates certify incapacity, they publish a joint assessment to the NRS and Acting Presidential Authority transfers immediately to the Senate Speaker"}, {"id": "s2-6-c", "num": "§2.6.c", "name": "Succession-Based Presidential Term", "text": "A person who assumes the presidency by succession under §2.6.a does not thereby expend their single non-renewable term. They must stand for election at the next regular National Election Day presidential cycle, or at a special presidential election called by the Legislature within 90 days of success"}, {"id": "s2-7", "num": "§2.7", "name": "Executive Transparency and NRS Obligations", "text": "Both executives must publish all official acts — orders, certifications, vetoes, objections, determinations — to the NRS within 48 hours of issuance. No executive may classify, delay, or suppress publication of an act this constitution requires to be published. Failure to publish within 48 hours is "}, {"id": "s2-8", "num": "§2.8", "name": "Emergency Governance Protocol", "text": "Where the Caretaker PM period extends beyond 90 days without a seated House — accounting for a 60-day election period and a 30-day seating grace period — the Senate automatically assumes joint emergency legislative authority by simple majority for three functions only: election administration, socia"}, {"id": "s2-8-a", "num": "§2.8.a", "name": "Expedited Activation", "text": "Where the Legislature has been physically unable to convene due to an attack on the seat of government or other catastrophic external event, the 90-day waiting period of §2.8 is waived. Expedited activation requires joint certification by the Caretaker PM and the most senior available Supreme Court "}, {"id": "s2-9", "num": "§2.9", "name": "Clemency and Amnesty", "text": "Clemency may only be granted within each executive's domain, with full transparency, and subject to cross-chamber review. Presidential clemency is subject to cross-chamber review under §2.9.c. Self-clemency is absolutely prohibited for all constitutional officers."}, {"id": "s2-9-a", "num": "§2.9.a", "name": "Legislative Amnesty", "text": "Only the Legislature may grant group amnesty, by simple majority of both chambers. No executive may grant group amnesty. Cannot extend to constitutional violations, official misconduct offenses, or crimes against the fundamental rights of §1.3 and §1.4. Subject to judicial review within 60 days of e"}, {"id": "s2-9-b", "num": "§2.9.b", "name": "Self-Clemency Absolute Prohibition", "text": "Self-clemency is absolutely prohibited. No elected or appointed official may grant clemency to themselves or to any person whose conviction, if enforced, would directly benefit the official financially, politically, or personally. An attempted self-clemency act is constitutionally void and itself a "}, {"id": "s2-9-c", "num": "§2.9.c", "name": "Cross-Chamber Clemency Review", "text": "Every clemency grant — whether by the President under §2.1.g or by the PM under §2.2.f — is subject to cross-chamber transparency review. Within 7 days of any grant, the granting executive files a written explanatory report with the EI stating: the identity of the recipient, the nature of the offens"}, {"id": "s2-10", "num": "§2.10", "name": "Presidential Removal — Two Political Tracks", "text": "The President may be removed on two independent tracks. The legislative track requires 2/3 of both chambers simultaneously following Inspectorate-certified findings. The popular track requires a Senate majority referral to a national recall referendum under §2.10.b."}, {"id": "s2-10-a", "num": "§2.10.a", "name": "Legislative Removal", "text": "Legislative removal grounds: verified constitutional breach, demonstrated permanent incapacity, or conviction for a disqualifying criminal offense. The LI and EI must jointly certify the grounds before a removal vote can proceed."}, {"id": "s2-10-b", "num": "§2.10.b", "name": "Senate Referral to Popular Recall", "text": "A simple majority of the full Senate membership may refer the question of presidential removal to a national recall referendum. The EC administers the referendum within 90 days of the Senate vote. The President is removed if 60% of votes cast are affirmative with at least 55% citizen participation. "}, {"id": "s2-10-c", "num": "§2.10.c", "name": "One Referral Per Term", "text": "No second Senate referral to popular recall within the same presidential term. One-shot rule prevents a hostile Senate from using repeated recall elections as attrition. After a failed recall, the President serves out their term with the NRS record intact."}, {"id": "s3-1", "num": "§3.1", "name": "The House of Representatives", "text": "The House of Representatives is the proportional chamber of the Legislature — directly elected by citizens on the basis of population. All legislation originates in the House and the PM is elected and accountable to it. Both States and Territories send voting members to the House. Territorial member"}, {"id": "s3-1-a", "num": "§3.1.a", "name": "House Seat Allocation — Webster Method", "text": "House seats are allocated by the Webster method: each State and Territory receives the number of seats nearest to its population divided by the Republic's standard constituency divisor, with a minimum of one seat per State or Territory regardless of population. The constituency divisor is set at 750"}, {"id": "s3-1-b", "num": "§3.1.b", "name": "Census Authority", "text": "The population census is conducted by the Legislative Inspectorate every ten years and whenever the Legislature requires reapportionment. Census methodology is published to the NRS before each census. Results are published to the NRS within 90 days of completion and used as the basis for House seat "}, {"id": "s3-1-c", "num": "§3.1.c", "name": "Single-Subject Rule", "text": "Every bill must address a single, clearly defined subject. Self-executing: a court finding that a bill addresses multiple unrelated subjects voids the entire act. The LI publishes a germaneness analysis for any amended bill returned to the House. No riders, no logrolling through combined legislation"}, {"id": "s3-1-d", "num": "§3.1.d", "name": "Bill Exposure", "text": "The full text of every bill must be published to the NRS for the minimum exposure period (Legislature defines by statute, not less than 7 days) before any final passage vote. A substantially amended bill resets the exposure clock."}, {"id": "s3-1-e", "num": "§3.1.e", "name": "Legislative Calendar and Session", "text": "The Legislature must sit for a minimum number of days per year defined by statute. Emergency sessions may be called by the PM or by petition of 1/3 of either chamber. Prevents pocket-session governance — the Legislature cannot be prorogued into ineffectiveness."}, {"id": "s3-1-f", "num": "§3.1.f", "name": "Legislative Compensation and Disclosure", "text": "Legislative compensation is set by the LI on a formula tied to median citizen income, not by the Legislature itself. All financial interests of members must be disclosed to the EI and published to the NRS. The compensation formula prevents legislators from voting themselves raises."}, {"id": "s3-1-g", "num": "§3.1.g", "name": "House Term Limits", "text": "No person may serve more than six consecutive 2-year terms in the House — a maximum of 12 consecutive years. After six consecutive terms, the member must sit out one full House electoral cycle (2 years) before standing again. After the cooling-off period, the member is again eligible with no further"}, {"id": "s3-2", "num": "§3.2", "name": "The Senate — States as Constitutional Actors", "text": "The Senate comprises two senators per State regardless of population, elected for 6-year staggered terms. The Senate serves as the checking chamber: it must act on every House-passed bill within the Legislature-defined period, may amend within the bounds of germaneness, and holds exclusive authority"}, {"id": "s3-2-a", "num": "§3.2.a", "name": "Senate Composition", "text": "Two senators per State regardless of population, elected by citizens of that State for 6-year staggered terms. No Senator may serve more than two consecutive terms (12 consecutive years). After two consecutive terms, a Senator must sit out one full term (6 years) before standing for Senate election "}, {"id": "s3-2-b", "num": "§3.2.b", "name": "Legislative Origination", "text": "All legislation must originate in the House. The Senate reviews, may amend within the bounds of germaneness, and may pass or decline — but may not initiate any bill. All revenue measures, appropriations, and debt ceiling changes must additionally originate in the House; the Senate may amend fiscal l"}, {"id": "s3-2-c", "num": "§3.2.c", "name": "Senate Must Act on Every House Bill", "text": "Senate Must Act — the Senate cannot table or indefinitely delay House-passed legislation. Must vote within the Legislature-defined period. If it does not act, Deemed Approval triggers automatically. The Senate may, by simple majority vote before the original review period expires, extend its review "}, {"id": "s3-2-d", "num": "§3.2.d", "name": "Judicial Confirmation", "text": "The Senate confirms all inferior court judicial appointments by a supermajority defined by statute (not less than 55%, not more than 67% of full Senate membership). Failure to vote within the confirmation period triggers Deemed Confirmation at 180 days. Supreme Court justice confirmation is governed"}, {"id": "s3-2-e", "num": "§3.2.e", "name": "Treaty Ratification", "text": "Treaty ratification requires a 2/3 majority of the full seated Senate."}, {"id": "s3-2-e-i", "num": "§3.2.e.i", "name": "Treaty Domestic Application", "text": "Where the Senate fails to ratify a treaty, if portions of the treaty's domestic provisions have standalone value independent of the international obligations, the President may transmit those portions to the House Speaker for consideration as ordinary domestic legislation. Prevents failed treaty rat"}, {"id": "s3-2-e-ii", "num": "§3.2.e.ii", "name": "Non-Disaggregable Treaties", "text": "Where a treaty is bilateral and designed as an integrated whole — with reciprocal obligations that are interdependent — the President may not disaggregate and transmit domestic provisions separately. The treaty must be renegotiated or abandoned in its entirety."}, {"id": "s3-2-e-iii", "num": "§3.2.e.iii", "name": "Treaty Withdrawal Process", "text": "The President may initiate withdrawal from any ratified treaty by publishing a formal notice of withdrawal to the NRS specifying the treaty, the effective withdrawal date (not less than 6 months from NRS publication), and the grounds. Withdrawal operates differently by treaty type: (a) General treat"}, {"id": "s3-2-f", "num": "§3.2.f", "name": "Senate Electoral Functions", "text": "The Senate administers the Presidential election in the absence of a functioning Elections Panel of the Digital Infrastructure Commission — as certified by the JI following a finding that the Elections Panel cannot administer a constitutionally valid election — presides over contested electoral proc"}, {"id": "s3-2-g", "num": "§3.2.g", "name": "Senate Internal Rules", "text": "The Senate defines its own internal procedures by standing order, subject to constitutional constraints. The presiding officer is the Speaker of the Senate, elected by Senate members. The Senate's procedural autonomy prevents the House from using procedural leverage to control Senate deliberation."}, {"id": "s3-2-h", "num": "§3.2.h", "name": "Senate Committees", "text": "Standing committees are constitutionally mandated for certain functions (the Senate Armed Services Committee for Tier 2 military authorization is the most significant). Committee composition must reflect chamber balance — no party may hold all seats on a standing committee."}, {"id": "s3-2-i", "num": "§3.2.i", "name": "Senate Amendment Authority", "text": "The Senate may amend House-passed bills, but amendments must be germane to the bill's subject matter. The LI publishes a germaneness analysis before the amended bill is returned to the House. The PM must give the LI's analysis due consideration during the Legislative Review Period. Non-germane amend"}, {"id": "s3-2-j", "num": "§3.2.j", "name": "Senate Speaker Role Limit", "text": "No Senator may serve as Speaker for more than three consecutive sessions (6 years). After three consecutive sessions as Speaker, the Senator must sit out at least one full session as a non-Speaker Senator before standing for Speaker again. This limit applies to the Speaker role only and does not aff"}, {"id": "s3-3", "num": "§3.3", "name": "Legislative Process and Passage", "text": "Bills become law by absolute majority of the full seated membership of both chambers; higher thresholds apply as specified."}, {"id": "s3-3-a", "num": "§3.3.a", "name": "Standard Passage", "text": "Bills pass by absolute majority of the full seated membership of both chambers, not just those present. The 'full seated membership' standard prevents passage by small quorums. Applies to ordinary legislation; higher thresholds apply to constitutional amendments, veto overrides, and removal proceedi"}, {"id": "s3-3-b", "num": "§3.3.b", "name": "Presidential Veto Override", "text": "Requires 2/3 of both chambers simultaneously. The simultaneous requirement means both chambers must vote in the same session. The SC reviews the presidential veto under §2.1.f.i before any override vote may proceed."}, {"id": "s3-3-c", "num": "§3.3.c", "name": "Record System Entry", "text": "The presiding officer of each chamber must certify and publish the final text of every enacted law to the NRS within 24 hours. All prior versions, committee reports, Inspectorate findings, and veto records are indexed alongside the enacted text. The NRS entry is the definitive legal record."}, {"id": "s3-3-d", "num": "§3.3.d", "name": "Legislative Mandate Enforcement", "text": "Where the constitution requires the Legislature to enact specific legislation by statute and the Legislature fails to do so within a specified period: the LI publishes a non-compliance finding; the mandate becomes justiciable in the SC; for mandates tied to constitutional rights, affected parties ma"}, {"id": "s3-4", "num": "§3.4", "name": "Electoral Districts", "text": "States draw their own House district maps following each census, subject to compliance review by the Legislative Inspectorate against the criteria established in §3.4.a. Where a State fails repeated review, the Electoral Commission draws an interim compliant map under §3.4.b pending State compliance"}, {"id": "s3-4-a", "num": "§3.4.a", "name": "Criteria Hierarchy", "text": "State district maps must meet five criteria: population equality within tolerance, geographic contiguity, compliance with §1.9 non-discrimination, no intentional dilution of minority voting power, and reasonable geographic compactness. States have discretion within these bounds — there is no single "}, {"id": "s3-4-b", "num": "§3.4.b", "name": "LI Redistricting Review", "text": "The LI reviews all State-drawn district maps within 60 days of submission and publishes its compliance findings to the NRS. If a map fails the §3.4.a criteria, the LI publishes specific findings and the State must submit a corrected map within 30 days. If the corrected map still fails, the Electoral"}, {"id": "s3-4-c", "num": "§3.4.c", "name": "Territorial District Drawing", "text": "For Territories holding one House seat, the Territory is a single at-large constituency — no district drawing is required and the EC administers the election directly through the NVS. For Territories holding two or more House seats, the Electoral Commission draws district boundaries following each c"}, {"id": "s3-4-e", "num": "§3.4.e", "name": "At-Large Seats", "text": "States with a small population may elect House members at-large rather than by district, if the LI determines that the minimum district size would make geographic districting meaningless. At-large elections use proportional representation mechanisms — no plurality winner-take-all at-large elections."}, {"id": "s3-4-f", "num": "§3.4.f", "name": "District Vacancy", "text": "When a House district seat falls vacant mid-term, the Electoral Commission administers a special election within 90 days. The replacement serves only the remainder of the original term. If fewer than 90 days remain in the term, the vacancy is not filled."}, {"id": "s3-4-g", "num": "§3.4.g", "name": "Redistricting Transparency", "text": "All State submissions, LI analyses, and interim maps must be published to the NRS throughout the redistricting process. Citizens have the right to submit commentary to the LI during the review period. Redistricting decisions are judicially reviewable under §4.3."}, {"id": "s3-4-h", "num": "§3.4.h", "name": "Redistricting Challenge", "text": "Any citizen, State government, or parliamentary minority of 1/3 may challenge a proposed district map by petitioning the SC within the 60-day review period after LI compliance certification. The Court reviews whether criteria were correctly applied — not whether a different map would have been bette"}, {"id": "s3-5", "num": "§3.5", "name": "The House — Composition and Structure", "text": "The House of Representatives is structured and administered as established in this section and §3.1."}, {"id": "s3-5-a", "num": "§3.5.a", "name": "House Membership Formula", "text": "Seat allocation follows the Webster method defined in §3.1.a. Where a reapportionment event creates or eliminates seats, the EC coordinates with affected States on district boundary adjustments before the next general election. The LI resolves any dispute between States about seat allocation methodo"}, {"id": "s3-5-b", "num": "§3.5.b", "name": "House Speaker", "text": "Elected by the House from among its members by absolute majority. Presides over House proceedings, manages the legislative calendar, and holds Acting Presidential Authority in the Presidential succession chain. The Speaker's dual role — legislative and succession — keeps the succession line within t"}, {"id": "s3-5-d", "num": "§3.5.d", "name": "House Quorum", "text": "A majority of the full seated House membership constitutes a quorum for ordinary business. The Speaker may compel attendance of absent members by warrant. No vote that requires an absolute majority of full membership may be held without quorum."}, {"id": "s3-6", "num": "§3.6", "name": "Legislative Oversight and Transparency", "text": "The Legislature operates under continuous Inspectorate oversight — the Inspectorates publish findings but do not direct legislative outcomes."}, {"id": "s3-6-a", "num": "§3.6.a", "name": "Inspectorate Access to Legislative Records", "text": "All three Inspectorates have full access to legislative records, committee deliberations, voting records, and draft legislation. The Legislature may not classify records from the Inspectorates."}, {"id": "s3-6-b", "num": "§3.6.b", "name": "LI Pre-Passage Constitutional Review", "text": "The LI publishes a constitutional analysis of any bill that appears to conflict with a constitutional provision, before the bill reaches a final vote. Advisory, not blocking — but creates a permanent NRS record that any member voting for the bill voted with full knowledge of the constitutional conce"}, {"id": "s3-6-c", "num": "§3.6.c", "name": "Committee Structure", "text": "Both chambers must maintain standing committees for their constitutionally assigned functions. Committees may not be abolished while they hold a constitutional mandate. The LI audits committee operations annually."}, {"id": "s3-6-d", "num": "§3.6.d", "name": "Joint Sessions", "text": "The two chambers may meet in joint session for constitutionally enumerated purposes: receiving Presidential addresses, certifying election results, and voting on constitutional amendments under Path A. Joint sessions do not allow mixing of the chambers' distinct functions."}, {"id": "s3-6-e", "num": "§3.6.e", "name": "Legislative Ethics and Conduct", "text": "The Legislature may establish a joint ethics committee with authority to sanction, suspend (not remove), or refer members to the EI for investigation. Removal requires a 2/3 vote of the relevant chamber following a published EI finding — the ethics committee cannot remove members, only the full cham"}, {"id": "s3-6-f", "num": "§3.6.f", "name": "Legislative Privilege", "text": "Members are privileged from civil arrest and civil suit arising from acts performed in their legislative capacity: votes, speeches, committee testimony. This privilege does not extend to criminal conduct, conduct outside legislative functions, or conduct the EI has certified as a constitutional brea"}, {"id": "s3-7", "num": "§3.7", "name": "Independent Statutory Officers", "text": "The constitution authorizes a class of statutory officers who operate independently of both executives. Their independence is structural — fixed terms, appointment from a JI-maintained registry, and removal only on the grounds specified in enabling statute."}, {"id": "s3-7-a", "num": "§3.7.a", "name": "Authorization", "text": "Statutory Independent Officers — the constitution authorizes the Legislature to create independent statutory offices outside both executive domains. They exercise regulatory, quasi-judicial, or administrative functions with constitutional independence — neither executive may direct their operations."}, {"id": "s3-7-b", "num": "§3.7.b", "name": "Appointment", "text": "Registry and Nomination for Independent Officers — the JI maintains a registry of qualified candidates for each independent statutory office. The PM may only nominate from the registry. The EI reviews each nominee's disclosure record for factual accuracy before Senate confirmation. Prevents purely p"}, {"id": "s3-7-c", "num": "§3.7.c", "name": "Senate Confirmation of Independent Officers", "text": "Confirmed by the Senate. Thresholds defined by the enabling statute within constitutional bounds. The Senate may not confirm an officer the EI has flagged for a material disclosure inaccuracy until the discrepancy is resolved."}, {"id": "s3-7-d", "num": "§3.7.d", "name": "Removal of Independent Officers", "text": "Removal requires a for-cause finding. The JI must publish a factual finding before any removal vote. The EI may certify the breach that triggers the proceeding, but the JI — which has no oversight relationship with the officer being removed — makes the independent factual finding for the removal pro"}, {"id": "s3-8", "num": "§3.8", "name": "Impeachment", "text": "The House may initiate impeachment proceedings against officers appointed to and serving in the President's executive domain, and against inferior court judges. The President is not subject to this section — presidential removal is governed exclusively by §2.10. The Prime Minister is not subject to "}, {"id": "s3-8-a", "num": "§3.8.a", "name": "Impeachment Inquiry", "text": "Any 1/3 minority of the House may open a formal impeachment inquiry. The inquiry is conducted by a House committee with findings published to the NRS. An inquiry carries no immediate consequences for the subject official. Inquiries lapse 120 days after opening if no Articles of Impeachment are filed"}, {"id": "s3-8-b", "num": "§3.8.b", "name": "Articles of Impeachment", "text": "The full House votes on Articles of Impeachment by absolute majority of full seated membership. Passage transmits the Articles immediately to the Senate and publishes them permanently to the NRS. The Articles must state specific grounds in plain language. The subject official continues in office pen"}, {"id": "s3-8-c", "num": "§3.8.c", "name": "Senate Trial", "text": "The President presides over Senate impeachment trials without voting on the final removal question. Where the President is the subject of proceedings under §2.10, the most senior available Supreme Court justice presides under the same conditions. The trial is conducted in public and recorded on the "}, {"id": "s3-8-d", "num": "§3.8.d", "name": "Executive Continuity During Impeachment", "text": "Impeachment of an officer within the President's executive domain activates the relevant succession protocols for that officer's functions from the date the House passes Articles, pending the Senate trial's conclusion. The impeached official retains personal Article I rights but is relieved of execu"}, {"id": "s4-1", "num": "§4.1", "name": "Court Structure", "text": "The Republic's judiciary operates at three levels: District Courts (fact-finding and evidence), Appellate Courts (rules compliance), and the Supreme Court (final constitutional authority). States may maintain specialized court structures by statute, provided any constitutional question arising in an"}, {"id": "s4-1-a", "num": "§4.1.a", "name": "Establishment", "text": "The House alone may create or abolish inferior courts by statute — one of the few exclusively House powers. The Senate confirms the judges who sit on those courts (§4.1.b), but the existence and structure of the courts is a House matter. The House may also define the jurisdiction and rules of inferi"}, {"id": "s4-1-b", "num": "§4.1.b", "name": "Appointment of Inferior Courts", "text": "The PM nominates inferior court judges within 90 days of a vacancy. The Senate confirms by a supermajority of 55–67% of full seated membership, as the Legislature defines by statute. Before the confirmation vote, the PM submits the nominee's disclosure record to the EI; the EI publishes its review b"}, {"id": "s4-1-c", "num": "§4.1.c", "name": "Judicial Tenure Protection", "text": "Inferior court judges, once commissioned, serve during good behavior with no fixed term. The Legislature may establish a maximum service age or maximum total service period (not less than 15 years from first commissioning), but may not create fixed-term appointments shorter than 15 years. Ensures ju"}, {"id": "s4-1-d", "num": "§4.1.d", "name": "Judicial Removal", "text": "Inferior court judges may be removed through three tracks: legislative removal by 2/3 of both chambers for constitutional breach or demonstrated incapacity; judicial discipline through a process the Legislature establishes by statute, subject to SC oversight; and criminal conviction for disqualifyin"}, {"id": "s4-1-e", "num": "§4.1.e", "name": "Supreme Court Composition and Size", "text": "The Supreme Court initially consists of nine justices. The Legislature may increase the number of justices by ordinary statute; any seat added is assigned to the class with the fewest current members — ties broken by public lot drawn by the JI — and must be filled through §4.2.d within 18 months of "}, {"id": "s4-2", "num": "§4.2", "name": "Supreme Court Selection", "text": "Supreme Court justices are nominated by the PM from the SC Candidate Registry and confirmed by the Senate by 2/3 supermajority of full seated membership. The Court is composed of the number of justices established under §4.1.e, organised into three staggered classes; each justice serves a single non"}, {"id": "s4-2-a", "num": "§4.2.a", "name": "Candidate Registration", "text": "Any citizen on the SC Candidate Registry (maintained by the JI under §8.4.e) may stand by filing a full disclosure record with the EI. The EI reviews within 14 days for factual accuracy — not to assess the quality of credentials. A candidate with a material inaccuracy is removed from the ballot; the"}, {"id": "s4-2-b", "num": "§4.2.b", "name": "Judicial Selection Board", "text": "Five senior judges (at least 10 years continuous service) chosen by lot by the JI from all eligible judges who are not themselves registered candidates. The Board may publish an advisory assessment of any registered candidate's judicial record, legal reasoning, and professional independence — on req"}, {"id": "s4-2-c", "num": "§4.2.c", "name": "Judicial Inspectorate Certification", "text": "The JI confirms that each candidate remains on the SC Candidate Registry and that no disqualifying change has occurred since Registry admission. Candidates who fail JI certification may appeal under §8.4.i."}, {"id": "s4-2-d", "num": "§4.2.d", "name": "PM Nomination and Senate Confirmation", "text": "The PM nominates a JI-certified candidate from the SC Candidate Registry. For scheduled vacancies, the PM must nominate within 60 days of the outgoing justice's term ending. For mid-term vacancies, the PM must nominate within 45 days of the vacancy arising. Within 30 days of nomination, the JI confi"}, {"id": "s4-2-e", "num": "§4.2.e", "name": "Mid-Term Vacancies", "text": "Any mid-term vacancy triggers immediate nomination under §4.2.d using the 45-day nomination window. The full process — PM nomination, JI assessment, and Senate confirmation — must be completed within 180 days of the vacancy. The replacement serves only the remainder of the original 12-year term — no"}, {"id": "s4-2-f", "num": "§4.2.f", "name": "Emergency Panel for Tier 1 Scope Challenges", "text": "Four justices are drawn by rotation each 2-year cycle. Sole jurisdiction over constitutional challenges to Tier 1 presidential military authority during active operations. Must rule within 48 hours. Binding on the full Court unless overruled within 72 hours. Ensures SC oversight during active crisis"}, {"id": "s4-2-g", "num": "§4.2.g", "name": "Vacancy Operating Rules", "text": "The most senior Appellate Court judge by continuous service is automatically designated as Temporary Associate Justice within 5 days of any SC vacancy, without nomination or confirmation. The Temporary Associate Justice holds a full vote in all cases and may not stand as a candidate for the seat the"}, {"id": "s4-2-h", "num": "§4.2.h", "name": "Initial Class Assignment", "text": "At Phase 3, the initial nine seats are filled simultaneously by PM nomination and Senate confirmation under §4.2.d, then assigned to three classes by public lot drawn by the JI. Class A: 4-year initial term. Class B: 8-year initial term. Class C: 12-year initial term. All subsequent terms: 12 years."}, {"id": "s4-2-i", "num": "§4.2.i", "name": "Judicial Recusal", "text": "The Legislature must by statute establish a recusal framework for Supreme Court justices within two years of Phase 4 activation. The framework must require recusal where a justice received material campaign support from any party to a pending case, or holds a financial interest in the outcome. A jus"}, {"id": "s4-3", "num": "§4.3", "name": "Judicial Independence and Scope", "text": "Courts act only on cases brought by a party with a concrete, articulable injury. Judges may not issue advisory opinions or preemptive rulings. All decisions altering legal status require full merits briefings and a published written decision. Judges apply the Constitution as written. Where the Const"}, {"id": "s4-3-a", "num": "§4.3.a", "name": "Judicial Review Authority", "text": "The SC (and inferior courts within their jurisdictions) has authority to declare legislative acts, executive orders, and administrative decisions unconstitutional and void. No political actor may override a constitutional ruling. The SC identifies the constitutional defect; the Legislature may respo"}, {"id": "s4-3-b", "num": "§4.3.b", "name": "Judicial Scope", "text": "Courts decide constitutional questions, not policy questions. The SC may not substitute its judgment for the Legislature's on policy matters — it may only determine whether the Legislature acted within its constitutional authority. A statute that is constitutionally permissible but poor policy is no"}, {"id": "s4-3-c", "num": "§4.3.c", "name": "Statutory Interpretation", "text": "Courts apply statutes to specific cases and resolve ambiguities. Where a statute is ambiguous, courts apply the interpretation most consistent with the constitution. Courts may not rewrite clear statutory language to produce a preferred outcome — they interpret, they do not legislate."}, {"id": "s4-3-d", "num": "§4.3.d", "name": "Original Jurisdiction", "text": "The SC has original (first-instance) jurisdiction over constitutional disputes between States, between a State and the federal government, and over challenges to the constitutional validity of a federal statute brought within 90 days of enactment. Certain cases bypass all lower courts and go directl"}, {"id": "s4-3-e", "num": "§4.3.e", "name": "Inspectorate Findings in Constitutional Proceedings", "text": "NRS findings published by the LI, EI, or JI are admissible as authoritative factual evidence in judicial proceedings. Courts must address any inconsistency between their factual findings and a prior Inspectorate finding in written decisions. Inspectorate findings are not judicial determinations — co"}, {"id": "s4-3-f", "num": "§4.3.f", "name": "Organizational Standing", "text": "An organization may bring a constitutional claim on behalf of its members where: (a) at least one member would individually have standing; (b) the claim is germane to the organization's established constitutional purpose; and (c) neither the claim nor the relief sought requires the participation of "}, {"id": "s4-4", "num": "§4.4", "name": "Judgment Recognition and Authentication", "text": "Judicial judgments, official records, and authenticated documents are recognized across all jurisdictions within the Republic. The NRS is the authentication infrastructure for this cross-jurisdictional recognition."}, {"id": "s4-4-a", "num": "§4.4.a", "name": "Judicial Judgments", "text": "Non-recognition grounds are exhaustive: the issuing court lacked jurisdiction; the judgment was obtained by fraud; or enforcement would require an act the Legislature has defined as categorically unenforceable. These three grounds are the only bases on which a Republic court may decline to recognize"}, {"id": "s4-4-b", "num": "§4.4.b", "name": "NRS Authentication", "text": "A judgment, order, or status record published to the NRS is self-authenticating in any other State or Territory court. No re-certification, notarization, or further authentication required. Eliminates the multi-state authentication burden that historically delayed enforcement of out-of-state judgmen"}, {"id": "s4-4-c", "num": "§4.4.c", "name": "Public Acts and Official Records", "text": "Official records published to the NRS are self-authenticating — no re-certification is required for use in any legal or administrative proceeding. Professional licenses issued by any State or Territory receive recognition across all States and Territories. §1.13 governs any State departure from the "}, {"id": "s4-4-d", "num": "§4.4.d", "name": "Status Orders — Special Protections", "text": "Protective orders, custody determinations, and other status orders take immediate effect in every State and Territory upon publication to the NRS. No waiting period, no local re-registration."}, {"id": "s4-4-e", "num": "§4.4.e", "name": "Non-Discrimination in Recognition", "text": "A State or Territory may not discriminate in its recognition of another jurisdiction's judgments or records based on the nature of the parties, the subject matter, or the legal status recognized by the issuing jurisdiction. Recognition is mandatory; non-recognition grounds are exhaustive under §4.4."}, {"id": "s4-4-f", "num": "§4.4.f", "name": "Legislative Implementation Mandates", "text": "A judgment is final for §4.4.a purposes if it is not subject to an automatic stay under the issuing jurisdiction's procedural law, regardless of whether an appeal is pending. The Legislature may refine the finality standard for specific categories but may not use pending-appeal status alone to block"}, {"id": "s4-5", "num": "§4.5", "name": "Jury Service", "text": "Citizens are required to serve on juries when called. Jury service is compensated at the national median daily income rate, as the Legislature defines by statute. Unexcused refusal is subject to civil consequences the Legislature defines by statute. Jury service does not constitute forced labor unde"}, {"id": "s5-1", "num": "§5.1", "name": "Citizenship", "text": "Citizenship is acquired by birth, by parentage, or by naturalization under the conditions of this section. Citizens hold the full rights established in Article I and are eligible to vote, hold office, and stand for election."}, {"id": "s5-1-a", "num": "§5.1.a", "name": "Inherent Citizenship", "text": "A child is automatically a citizen at birth if at least one parent is a Citizen or Legal Resident at the time of birth. Statelessness prevention clause: where a child would otherwise be stateless, citizenship is granted regardless of parental status. No citizenship may be stripped from a natural-bor"}, {"id": "s5-1-a-i", "num": "§5.1.a.i", "name": "Statelessness Prevention", "text": "A child born on Republic territory to parents holding neither Citizen nor Legal Resident status is an Inhabitant from birth, with full Article I protections and access to social state systems under §10.1. Where no country recognizes the child as a citizen, the Republic provides a determination proce"}, {"id": "s5-1-b", "num": "§5.1.b", "name": "Coming of Age", "text": "Children of citizens are Inhabitants at birth with full Article I protections. Full citizenship rights — including the right to vote — activate at 18."}, {"id": "s5-1-c", "num": "§5.1.c", "name": "Naturalization", "text": "A Legal Resident may earn citizenship after five continuous years of residency, a clean legal record, and passing the Constitutional Logic Test."}, {"id": "s5-1-d", "num": "§5.1.d", "name": "National Service Path", "text": "A Legal Resident may earn citizenship through honorable completion of military or national service — a service path that runs parallel to the residency path."}, {"id": "s5-1-e", "num": "§5.1.e", "name": "Citizenship Irrevocability", "text": "Citizenship may not be revoked as punishment or for any reason once granted by birth or naturalization. The Republic may not manufacture statelessness as a punitive tool. See also §5.1.a.i, which ensures children born on Republic territory to undocumented parents cannot be left stateless by inaction"}, {"id": "s5-1-f", "num": "§5.1.f", "name": "Derivative Status", "text": "A child born before a parent acquired Legal Residency or Citizenship, who accompanies that parent to the Republic within a Legislature-defined window, receives derivative status. Prevents a parent's pre-Republic legal status from permanently cutting off their child's path to citizenship."}, {"id": "s5-1-g", "num": "§5.1.g", "name": "Accelerated Naturalization — Long-Term Pre-Ratification Residents", "text": "Any person who resided continuously in the Republic's territory for five or more years immediately before Day Zero but did not hold predecessor voting rights — including persons disenfranchised by laws subsequently nullified under §19.2 — may apply for citizenship through an accelerated process the "}, {"id": "s5-2", "num": "§5.2", "name": "Legal Resident Rights", "text": "Legal Residents hold a Residency Credential allowing them to work, enter contracts, own property, access social state systems under §10.1, and participate in local elections where the Legislature authorizes. They hold all Article I rights as Inhabitants. What they lack that citizens hold: federal vo"}, {"id": "s5-3", "num": "§5.3", "name": "Custodial Care of Citizen Children", "text": "Where a parent or guardian who is the primary caregiver of a citizen child is removed from the Republic, the Republic accepts responsibility for that citizen child — housing, care, and connection to remaining family. The Republic does not separate citizen children from their sole caregivers without "}, {"id": "s5-4", "num": "§5.4", "name": "The Constitutional Logic Test", "text": "The CLT is required for earned citizenship through naturalization (§5.1.c) and national service (§5.1.d). It tests knowledge of constitutional principles and civic structure — not political opinions or cultural loyalty. The Senate deadlock rule (§5.4.c) ensures the existing test remains in force if "}, {"id": "s5-4-a", "num": "§5.4.a", "name": "Senate Authority over the CLT Standard", "text": "The CLT must assess knowledge sufficient to understand the structure, powers, limits, and rights established by this Constitution. Any statute reducing the CLT below this floor is void and any citizen may challenge it in court. The Senate sets the CLT standard by statute — raising it by simple major"}, {"id": "s5-4-b", "num": "§5.4.b", "name": "CLT Administrator", "text": "The Constitutional Logic Test is administered by a CLT Administrator nominated by the PM from a Candidate Register, confirmed by the Senate. Structural independence from partisan influence: the CLT process cannot be used to create barriers that track political outcomes."}, {"id": "s5-4-c", "num": "§5.4.c", "name": "Status Quo Maintenance", "text": "Senate deadlock on CLT standard changes keeps the existing version in force."}, {"id": "s5-5", "num": "§5.5", "name": "Founding Generation Citizenship", "text": "All individuals holding voting rights on Day Zero of ratification are automatically granted full citizenship as founding members of the Republic, as established in §5.5.a."}, {"id": "s5-5-a", "num": "§5.5.a", "name": "Automatic Citizenship Grant", "text": "All individuals holding voting rights on Day Zero of ratification are automatically granted full citizenship without testing or application. The Day Zero Grandfather Clause prevents the new Republic from immediately disenfranchising its existing population by requiring existing voters to re-qualify "}, {"id": "s6-1", "num": "§6.1", "name": "The Dual-Gate System", "text": "Every immigration application must clear two sequential gates: Gate 1 (State sponsorship) and Gate 2 (federal certification). Legal residency requires passing both gates. Gate 1 is State acceptance — States retain discretion over whom they sponsor, but may not apply sponsorship criteria that violate"}, {"id": "s6-1-a", "num": "§6.1.a", "name": "Gate 1 — State Sponsorship", "text": "A sponsoring State certifies the applicant through its own vetting process and accepts notification obligations during the application period. During the application period the applicant must maintain a genuine connection to the sponsoring State — as the Legislature defines by statute — so that noti"}, {"id": "s6-1-b", "num": "§6.1.b", "name": "Gate 2 — Federal Certification", "text": "Federal certification covers four statutory categories: identity verification, criminal history, national security assessment, self-sufficiency or support guarantee. Cannot impose ideological screening or nationality-based quotas. Any denial must specify the precise ground in writing. National secur"}, {"id": "s6-1-c", "num": "§6.1.c", "name": "Presidential Role", "text": "Once an applicant clears both gates, the President must ministerially issue residency credentials. Presidential interference with credential issuance is constitutionally prohibited."}, {"id": "s6-1-d", "num": "§6.1.d", "name": "Federal Sponsorship Category", "text": "The Legislature may establish a Federal Sponsorship Category where designated federal agencies serve as Gate 1 sponsors for applicants whose skills directly serve a defined federal interest — research programs, national infrastructure, national security-adjacent technical roles. The agency assumes a"}, {"id": "s6-2", "num": "§6.2", "name": "Enforcement and Removal", "text": "Only the federal government may remove individuals from the Republic — States may not conduct deportations independently. Removal occurs only for violations of laws the Legislature has defined — executive detention without statutory basis is not removal, it is unlawful detention subject to habeas co"}, {"id": "s6-3", "num": "§6.3", "name": "Gate 2 Appeal Rights", "text": "Gate 2 denials are judicially challengeable on three grounds: criterion outside the four certified categories; denial made on discriminatory grounds contrary to §1.9; or procedural violation affecting the outcome. Gate 1 denials are not reviewable on the merits of the sponsorship decision — a State'"}, {"id": "s6-3-a", "num": "§6.3.a", "name": "Judicial Challenge", "text": "An applicant may challenge a Gate 2 denial on three grounds: criterion outside the four certified categories; discriminatory application; or procedurally deficient process."}, {"id": "s6-3-b", "num": "§6.3.b", "name": "National Security Denials — In-Camera Review", "text": "Where Gate 2 is denied on national security grounds, a reviewing court may examine the classified assessment in camera and determine whether it constitutes a credible, specific, and documented security concern — without publishing classified content. The in-camera determination is outcome-determinat"}, {"id": "s6-4", "num": "§6.4", "name": "Asylum and Protection", "text": "Asylum proceedings operate on a separate constitutional track from the dual-gate immigration system. An asylum filer under §1.28 becomes an Inhabitant at filing — not upon grant. Their claim must be determined before any removal order takes effect. The asylum track is explicitly exempt from Gate 1 s"}, {"id": "s6-4-a", "num": "§6.4.a", "name": "Asylum Seekers as Inhabitants", "text": "Any person who files an asylum claim under §1.28 is an Inhabitant of the Republic from the date of filing — immediately entitled to access social state systems under §10.1 and all Article I protections. Protection-first: the determination process does not happen in a rights-free zone."}, {"id": "s6-4-b", "num": "§6.4.b", "name": "Right to Determination and Protection During Proceedings", "text": "Asylum proceedings must provide: a qualified adjudicator with decision authority, access to an interpreter, the right to present evidence and witnesses, a written decision specifying grounds, and a right of appeal. Standards apply regardless of the applicant's point of entry into the Republic."}, {"id": "s6-4-c", "num": "§6.4.c", "name": "Asylum Court", "text": "The Asylum Court is a federal judicial institution constitutionally independent of both executive branches. Its judges hold full tenure protections. The Legislature may not establish any asylum determination body as a subdivision or instrumentality of either executive branch — administrative asylum "}, {"id": "s6-4-d", "num": "§6.4.d", "name": "Non-Penalization for Irregular Entry", "text": "The manner or means of entry into the Republic — including irregular or unauthorized entry — does not affect the right to claim asylum or have that claim determined. No penalty arising solely from irregular entry may be imposed on a person whose asylum claim is pending or has been granted."}, {"id": "s6-4-e", "num": "§6.4.e", "name": "Unexecutable Removal Orders", "text": "Legislature must define a minimum status, material conditions, and periodic judicial review for persons subject to final removal orders that cannot be executed — because the destination country won't accept them, or execution would violate §1.28. The constitution does not allow indefinite stateless "}, {"id": "s6-4-f", "num": "§6.4.f", "name": "Security and Criminal Protection Cases", "text": "Where the Asylum Court grants §1.28 protection to a person who poses a documented security threat, removal remains constitutionally barred. Indefinite unreviewed detention is not a constitutionally available outcome. Where removal is barred under §1.28 and a documented security threat is established"}, {"id": "s6-4-g", "num": "§6.4.g", "name": "Territory Accessibility", "text": "The asylum proceedings statute must ensure asylum is accessible to persons in Territories and geographically remote areas — not just major population centers. The right to seek asylum applies regardless of where in the Republic a person arrives."}, {"id": "s6-4-h", "num": "§6.4.h", "name": "Unaccompanied Minors", "text": "An unaccompanied minor arriving in the Republic or presenting to Republic authorities is an Inhabitant from the moment of contact and holds full §1.28 protection. A federal legal guardian must be appointed within 24 hours. No unaccompanied minor may be detained in a facility not specifically designa"}, {"id": "s7-1", "num": "§7.1", "name": "Standard Elections — Ranked Choice", "text": "All federal elections on National Election Day, every two years. All elections for House, Senate, and Director of the Digital Infrastructure Commission use Ranked Choice Voting — majority required, not plurality. No federal elections outside National Election Day except special elections for vacanci"}, {"id": "s7-2", "num": "§7.2", "name": "Presidential Election System", "text": "The President is elected through two concurrent requirements: a national RCV majority and a State plurality qualification. A candidate wins outright by satisfying both. Where a candidate's national RCV majority exceeds 60% of active ballots, the State plurality requirement is waived — a margin of th"}, {"id": "s7-2-a", "num": "§7.2.a", "name": "National Ranked-Choice Vote", "text": "Presidential elections use Ranked Choice Voting conducted nationally. Votes transfer until one candidate holds a majority of active ballots nationwide. The Elections Panel of the Digital Infrastructure Commission administers the national election and certifies results under §7.2.e."}, {"id": "s7-2-b", "num": "§7.2.b", "name": "State Plurality Requirement", "text": "A candidate satisfies the State plurality requirement by receiving more first-preference votes than any other candidate in a majority of the Republic's States. Where the national RCV majority exceeds 60% of active ballots, this requirement is waived under §7.2. Territory votes count toward the natio"}, {"id": "s7-2-d", "num": "§7.2.d", "name": "Territory Presidential Voting", "text": "Territory citizens hold the full §1.20 right to vote in presidential elections. Their votes count in the national first-preference total and RCV calculation. Territories are not included in the State plurality calculation under §7.2.b — their citizens are not residents of a State for this purpose. T"}, {"id": "s7-2-e", "num": "§7.2.e", "name": "Election Certification", "text": "The Electoral Commission certifies the final presidential election result to the NRS within a period the Legislature defines by statute. Certification is final and may be challenged only before the Supreme Court within 14 days. No transfer of presidential authority may be delayed beyond the moment e"}, {"id": "s7-2-f", "num": "§7.2.f", "name": "Run-off", "text": "Where no candidate wins outright — either because no candidate achieved a national RCV majority, or because the national majority winner's margin did not exceed 60% of active ballots and the candidate failed the State plurality requirement — a runoff is conducted between the two candidates with the "}, {"id": "s7-3", "num": "§7.3", "name": "Legislative Elections", "text": "Legislative elections are administered by the Electoral Commission free from executive interference. The National Voting System is the uniform platform for all federal elections."}, {"id": "s7-3-a", "num": "§7.3.a", "name": "No Executive Interference", "text": "The President may not declare, postpone, or influence the scheduling of elections — including declaring emergencies that have the effect of postponing them."}, {"id": "s7-3-b", "num": "§7.3.b", "name": "National Voting System", "text": "The Electoral Commission administers the National Voting System through which all federal elections and referenda are conducted. The NVS is constitutionally required to maintain ballot secrecy, public auditability, and resilience — properties defined in Article XVI creating a cross-constitutional gu"}, {"id": "s7-3-c", "num": "§7.3.c", "name": "Participation Protection", "text": "No State may take any action that reduces NVS access, functionality, or availability within its territory. State-level voter suppression — long lines, ID requirements that function as bars, polling place closures that reduce access — is constitutionally prohibited to the extent it reduces access for"}, {"id": "s8-1", "num": "§8.1", "name": "Three Inspectorates", "text": "The Republic maintains three constitutionally independent Inspectorates — Legislative, Executive, and Judicial — each selected by branches other than those it oversees. The Inspectorates hold an information-only mandate: they publish findings but do not issue binding orders. Each Inspector General s"}, {"id": "s8-1-a", "num": "§8.1.a", "name": "The Legislative Inspectorate (LI)", "text": "The LI audits the Legislature for fiscal accuracy, constitutional compliance, and NRS integrity. Conducts the population census (assigned to the LI because the census determines House seat allocation — giving this to a body nominated by the House would be a direct conflict of interest). Reviews Hous"}, {"id": "s8-1-b", "num": "§8.1.b", "name": "The Executive Inspectorate (EI)", "text": "The EI audits both executives and the Monetary Authority. Annual military compliance assessment: were Tier authorizations followed? Was §1.30.d Intelligence Firewall maintained? Were fund certifications observed? Publishes clemency background reports before any executive act. Reviews disclosure reco"}, {"id": "s8-1-c", "num": "§8.1.c", "name": "The Judicial Inspectorate (JI)", "text": "The JI audits the courts for judicial scope and independence. Maintains the SC Candidate Registry. Vets judicial nominees and Electoral Commission candidates. Audits the Digital Infrastructure Commission annually. Reviews accommodation compact compliance under §19.1, Associated Community compact com"}, {"id": "s8-2", "num": "§8.2", "name": "Selection and Independence", "text": "Each Inspectorate is constituted through a cross-nomination process that structurally excludes the body being watched from selecting those who watch it. The Supreme Court nominates the LI Inspector General, confirmed by Senate 2/3 supermajority. The House nominates the EI Inspector General, confirme"}, {"id": "s8-3", "num": "§8.3", "name": "Inspector General Selection", "text": "Each Inspector General is selected through a cross-nomination process that excludes the body being watched, as specified in §8.3.a through §8.3.c."}, {"id": "s8-3-a", "num": "§8.3.a", "name": "Legislative IG", "text": "The LI Inspector General is nominated by the Supreme Court, confirmed by the Senate by 2/3 supermajority. The House is entirely excluded — the body whose seat allocation the census determines has no role in selecting the office that conducts the census. The 2/3 Senate threshold ensures the LI IG com"}, {"id": "s8-3-b", "num": "§8.3.b", "name": "Executive IG", "text": "The EI Inspector General is nominated by the House, confirmed by the Senate by simple majority, with JI vetting of the nominee's disclosure record before the confirmation vote. The House nominates the EI because the PM — whom the EI watches — is accountable to the House, creating structural alignmen"}, {"id": "s8-3-c", "num": "§8.3.c", "name": "Term and Staggering", "text": "All IGs serve 10-year non-renewable terms. No two IG terms may begin within 18 months of each other, ensuring continuous institutional knowledge. An outgoing IG may not be reappointed to the same office. The stagger means the system never faces simultaneous turnover in multiple offices."}, {"id": "s8-4", "num": "§8.4", "name": "Judicial Inspectorate — Audit and Certification Mandate", "text": "The Judicial Inspectorate holds two constitutional mandates. First, as auditor: it monitors the court system, administers the SC candidate registry, and conducts compliance audits across compact obligations. Second, as certification administrator: it certifies lottery draws and panel selections thro"}, {"id": "s8-4-a", "num": "§8.4.a", "name": "Judicial IG Candidate Pool", "text": "The JI Inspector General is drawn by public lottery from a qualified candidate pool. The outgoing JI IG administers the draw, witnessed by the other two IGs and three citizens chosen by jury protocols. Published to the NRS immediately. No political body nominates the JI IG — the most structurally in"}, {"id": "s8-4-b", "num": "§8.4.b", "name": "JI Compact Compliance Audit", "text": "Annual compliance reviews for §19.1 accommodation compacts, Article XX Associated Community compacts, and Article XIV indigenous compact obligations. The JI verifies that Article I rights protections are being maintained and that compact terms are being honored by both parties."}, {"id": "s8-4-c", "num": "§8.4.c", "name": "JI Court Operations Audit", "text": "Annual audit of the court system for judicial scope compliance, independence from political pressure, and proper administration of judicial functions. The JI does not audit judicial reasoning — it audits whether courts are operating within their constitutional mandate and free from inappropriate inf"}, {"id": "s8-4-d", "num": "§8.4.d", "name": "JI Electoral Commission Audit", "text": "Annual audit of the EC for electoral integrity compliance, administrative accuracy, and independence. Distinct from the EI's executive compliance audit — the JI focuses on electoral administration integrity. Published to the NRS as a standalone annual report."}, {"id": "s8-4-e", "num": "§8.4.e", "name": "Supreme Court Candidate Registry", "text": "The JI maintains the standing registry from which SC candidates are drawn. Any citizen meeting the eligibility criteria (15+ years legal practice or 10+ years judicial service, no current government position, no disqualifying financial interest) may apply. Applications reviewed within 21 days. Regis"}, {"id": "s8-4-f", "num": "§8.4.f", "name": "JI Judicial Independence Audit", "text": "Annual published audit of the entire court system. The JI audits the independence of the process, not judicial reasoning or outcomes: are judges free from political pressure? Are proper recusal procedures being followed? Are ex parte communications being reported? Are court appointments following co"}, {"id": "s8-4-g", "num": "§8.4.g", "name": "SC Independence Assessment", "text": "Within the annual judicial audit, the JI publishes a specific assessment of SC independence: the integrity of the SC election process; any attempts to influence SC candidates before election; any contacts between SC justices and political actors not disclosed to the NRS; the adequacy of the SC's int"}, {"id": "s8-4-h", "num": "§8.4.h", "name": "Inferior Court Compliance", "text": "The JI audits inferior courts for compliance with their jurisdictional limits under §4.3.b. Courts that repeatedly exceed their jurisdictional scope, or demonstrate a pattern of failing to apply constitutional standards, are flagged in the JI annual report. The JI identifies systemic compliance issu"}, {"id": "s8-4-i", "num": "§8.4.i", "name": "Gatekeeping Appeal", "text": "Any candidate removed from a ballot by the JI's certification function may appeal to the Appellate Court within 14 days. The Court reviews only whether the JI correctly applied the eligibility criteria. Must rule within 21 days. If the removal is found improper, the candidate is reinstated to the ba"}, {"id": "s8-5", "num": "§8.5", "name": "Inspector General Removal", "text": "An Inspector General may be removed only through the mechanisms specified in this section."}, {"id": "s8-5-a", "num": "§8.5.a", "name": "For-Cause Removal", "text": "For-cause removal of an Inspector General requires a 2/3 vote of both chambers simultaneously, preceded by a substantiated finding from a State Designee Panel under §8.9.f. Duty suspension triggers upon publication of a substantiated Panel finding, pending the legislative vote and any SC review. The"}, {"id": "s8-5-b", "num": "§8.5.b", "name": "No-Cause Removal", "text": "Any IG may be removed without cause by 3/4 of both chambers simultaneously, except the Judicial Inspectorate IG under §8.5.c, whose lottery-based selection makes no-cause removal equivalent to a political veto over the draw result. The higher threshold (3/4 vs 2/3 for cause) ensures no-cause removal"}, {"id": "s8-5-c", "num": "§8.5.c", "name": "Judicial IG — For-Cause Only", "text": "The JI IG may only be removed for cause; no-cause removal is not available. The JI's lottery-based selection and its role in judicial independence oversight makes it the most insulated of the three offices."}, {"id": "s8-6", "num": "§8.6", "name": "Inspectorate Operations and Mandate", "text": "The three Inspectorates operate under a shared information-only mandate: they observe, audit, and publish."}, {"id": "s8-6-a", "num": "§8.6.a", "name": "Information-Only Mandate", "text": "Inspectorates publish facts; they do not issue binding orders or legal determinations. A finding that a government actor has breached the constitution is a factual statement, not a judgment."}, {"id": "s8-6-b", "num": "§8.6.b", "name": "NRS Publication Requirement", "text": "Every Inspectorate finding, report, and discrepancy notice must be published to the NRS permanently and free of charge. No official may suppress, delay, classify, or alter an Inspectorate Report before publication. The publication requirement is absolute."}, {"id": "s8-6-c", "num": "§8.6.c", "name": "Minority Reports", "text": "Any staff member may publish a Minority Report directly to the NRS if they believe a finding has been improperly omitted or suppressed by the IG. Staff cannot be disciplined for filing a Minority Report — the protection is absolute. Creates an internal whistleblower mechanism within the Inspectorate"}, {"id": "s8-6-d", "num": "§8.6.d", "name": "Classification Exemption for Inspectorate Reports", "text": "Inspectorate Reports are permanently exempt from classification. If an investigation involves classified material, the Report describes the issue's nature without reproducing classified content and flags it for the relevant executive. The classification exemption is one of the few absolute rules in "}, {"id": "s8-6-e", "num": "§8.6.e", "name": "Annual State of the Republic Report", "text": "The three Inspectorates jointly publish an annual report on a constitutionally fixed date, regardless of whether any political actor requests it. Covers compliance rates, investigation summaries, constitutional strains, and a forward-looking risk register. No government actor may delay, suppress, or"}, {"id": "s8-6-f", "num": "§8.6.f", "name": "Joint Investigation Authority", "text": "Where a compliance question spans multiple Inspectorate mandates, the Inspectorates may conduct a joint investigation. Joint findings are published as a combined report. Neither IG may veto the other's contribution to a joint finding."}, {"id": "s8-6-g", "num": "§8.6.g", "name": "Investigative Access", "text": "All three Inspectorates have unrestricted access to records, personnel, facilities, and systems within their audit mandate. No official may obstruct, delay, or impede an Inspectorate investigation. Obstruction is a constitutional breach reportable by the affected Inspectorate to the NRS."}, {"id": "s8-7", "num": "§8.7", "name": "Triggered Investigations", "text": "The EI may investigate a constitutional officer for dereliction: failure to perform a constitutionally mandated function. Dereliction is distinct from breach — breach is doing something unconstitutional, dereliction is failing to do something constitutionally required. The EI publishes its derelicti"}, {"id": "s8-7-a", "num": "§8.7.a", "name": "Official Trigger", "text": "Dereliction requires: (a) the constitutional function is clearly established; (b) the officer failed to perform it within the constitutionally required period; and (c) the failure was not caused by circumstances genuinely beyond the officer's control. Political disagreement with a constitutional req"}, {"id": "s8-8", "num": "§8.8", "name": "EI Annual Military Assessment", "text": "A dedicated section within the EI's annual report covering: whether military operations in the prior year were authorized through the correct Tier; whether the §1.30.d Intelligence Firewall was maintained; whether PM fund certifications were obtained and observed; whether the 48-hour NRS publication"}, {"id": "s8-9", "num": "§8.9", "name": "State Designee Panel", "text": "The State Designee Panel is a verification body constituted per proceeding whose sole function is to determine, before any qualifying For-Cause removal vote, whether the stated grounds are substantiated within the enumerated constitutional categories for that office. The Panel publishes a binary fin"}, {"id": "s8-9-a", "num": "§8.9.a", "name": "State Designee Pools", "text": "Each State maintains a standing State Designee Pool. Eligibility requires: at least five continuous years of Republic citizenship; no current federal elected or appointed office; no such office held within the three years prior to pool entry; no pending federal criminal proceedings; and no current s"}, {"id": "s8-9-d", "num": "§8.9.d", "name": "Panel Constitution", "text": "Upon activation of a qualifying proceeding, the JI constitutes the Panel by public lottery within five days, drawing five members from the combined national pool plus two alternates, in a single session certified jointly by all three Inspectorates and published to the NRS in real time. Members must "}, {"id": "s8-9-f", "num": "§8.9.f", "name": "Activation and Meeting Parameters", "text": "A qualifying proceeding is initiated when the initiating body transmits the stated grounds and supporting documentary record to the JI, triggering the draw under §8.9.d. The 21-day review clock begins when the Panel is fully constituted — five members having accepted service. The Legislature defines"}, {"id": "s8-9-g", "num": "§8.9.g", "name": "Scope of Review", "text": "The Panel determines only whether the stated grounds, as documented in the submitted record, constitute at least one of the enumerated constitutional categories for For-Cause removal applicable to the subject office. The Panel does not independently investigate, assess credibility, weigh competing f"}, {"id": "s8-9-h", "num": "§8.9.h", "name": "Effect of Finding", "text": "A finding of grounds substantiated: authorizes the Legislature to proceed to a For-Cause removal vote at the applicable threshold; triggers applicable duty suspension under §8.5.a, §10.4.g, or §16.2.a; and is published permanently to the NRS. A finding of unsubstantiated: does not bar a removal vote"}, {"id": "s8-9-i", "num": "§8.9.i", "name": "SC Review", "text": "Any named officer subject to a Panel finding may petition the Supreme Court for review within 14 days of NRS publication. The Court reviews only whether the Panel correctly applied the constitutional categories to the submitted record — it does not review the substance of the underlying grounds, the"}, {"id": "s8-10", "num": "§8.10", "name": "Inspectorate Minimum Funding Guarantee", "text": "The annual appropriation for each Inspectorate may not fall below the prior fiscal year's funding level without a 2/3 vote of both chambers simultaneously. This floor ensures that Inspectorate independence cannot be undermined through budgetary attrition by the branches they audit. The Monetary Auth"}, {"id": "s8-11", "num": "§8.11", "name": "Eighth-Year Assessment", "text": "Every eight years from the date of full constitutional operation, the three Inspectorates jointly assess the performance of the constitutional framework across all domains: (1) enforcement of Article I rights across all States, Territories, and compact jurisdictions; (2) functioning of the Inspector"}, {"id": "s9-1", "num": "§9.1", "name": "NRS Properties", "text": "The National Record System is the permanent, tamper-evident public record of the Republic — freely accessible to every Inhabitant at no cost. Every government act required to be published must appear on the NRS before it takes legal effect. An act not on the NRS is constitutionally suspect. The NRS "}, {"id": "s9-1-a", "num": "§9.1.a", "name": "Immutability", "text": "Records published to the NRS may not be deleted, altered, or reclassified after publication. Corrections are published as new entries alongside the original, not as replacements. The full history of any government act — including corrections, amendments, and subsequent interpretations — is permanent"}, {"id": "s9-1-b", "num": "§9.1.b", "name": "NRS Access", "text": "Freely accessible to every Inhabitant at no cost. No registration, no fees, no identification required for read access. The Republic must provide free public access terminals in every State and Territory. The NRS is not a luxury service — it is the mechanism by which Inhabitants verify that governme"}, {"id": "s9-1-c", "num": "§9.1.c", "name": "Public Accessibility", "text": "Every category of government act required to be published must be published within the time specified by the constitution or enabling statute. Acts not published within their required period are not void (except where the constitution specifically provides otherwise), but the publication failure is "}, {"id": "s9-1-d", "num": "§9.1.d", "name": "NRS Technical Standards", "text": "The Legislature must by statute define the technical standards: format, metadata requirements, search and retrieval standards, and backup and redundancy requirements. The standards must ensure the NRS remains fully functional in the event of a localized technical failure. No single point of failure "}, {"id": "s9-1-e", "num": "§9.1.e", "name": "NRS Integrity Audit", "text": "The LI audits NRS integrity annually, verifying that: all required publications have been made; no records have been altered or deleted; search and retrieval functions are operating correctly; and access is genuinely free and unrestricted."}, {"id": "s9-1-f", "num": "§9.1.f", "name": "Third-Party NRS Mirrors", "text": "The Legislature may authorize non-governmental organizations to maintain verified mirrors of the NRS for redundancy. Mirrors must meet the same technical standards as the primary NRS. The primary NRS remains a government function — the authorization does not create a privatization pathway."}, {"id": "s9-1-g", "num": "§9.1.g", "name": "NRS Classification Exemption", "text": "Inspectorate Reports published to the NRS are permanently exempt from classification, consistent with §8.6.d. The NRS itself may not apply classification restrictions to Inspectorate Reports — the publication platform cannot override the content exemption."}, {"id": "s9-1-h", "num": "§9.1.h", "name": "Cross-Jurisdictional Record Recognition", "text": "Records published to the NRS by any jurisdiction within the Republic are recognized as authentic records by all other jurisdictions without re-certification, apostille, or additional verification. The NRS publication is the authentication. A court, agency, or official that refuses to recognize an NR"}, {"id": "s9-2", "num": "§9.2", "name": "Historical Records Preservation", "text": "The NRS includes a permanent historical archive of all prior legislative acts, executive orders, judicial decisions, and government documents dating to the Republic's founding. The Legislature may not delete records from the historical archive — it may annotate them to indicate supersession or repea"}, {"id": "s9-3", "num": "§9.3", "name": "Digital Infrastructure Advisory Council", "text": "The National Record System and the National Voting System are reviewed decennially by the Digital Infrastructure Advisory Council — an independent expert body that publishes advisory findings and recommendations to the Digital Infrastructure Commission. The Advisory Council has no authority to issue"}, {"id": "s9-3-a", "num": "§9.3.a", "name": "Advisory Council — Mandate and Trigger", "text": "The Advisory Council reviews whether the NRS and NVS architectures continue to meet their respective constitutional requirements under §9.1 and §16.3. The Council convenes every ten years from the date of the first Legislature convening under §19.3.d. Qualifications for pool eligibility, audit metho"}, {"id": "s9-3-b", "num": "§9.3.b", "name": "Advisory Pool — State Nominations", "text": "Each State may nominate any number of qualified persons to the Digital Infrastructure Advisory Pool at any time. Nominations are submitted to the JI, which reviews each nominee and publishes a qualification report to the NRS within 30 days — assessing whether the nominee holds relevant expertise in "}, {"id": "s9-3-c", "num": "§9.3.c", "name": "Pool Reset", "text": "The Advisory Pool resets after each decennial review cycle. States may re-nominate the same persons with fresh JI qualification certification, or submit new nominees. Members who served on the Advisory Council are eligible for re-nomination by their State after one full cycle has elapsed since their"}, {"id": "s9-3-d", "num": "§9.3.d", "name": "Advisory Council Draw", "text": "When the decennial review is triggered, all three Inspectorates jointly constitute the Council by public lottery, drawing five members at random from the eligible pool. The draw is conducted in a public session; all three Inspectorates certify the result and publish it to the NRS before the session "}, {"id": "s9-3-e", "num": "§9.3.e", "name": "Advisory Council Member Replacement", "text": "If an Advisory Council member must be replaced during the review period — through ineligibility, withdrawal, or disqualification — all three Inspectorates draw one replacement at random from the remaining eligible pool members using the same public lottery procedure under §9.3.d. The replacement mem"}, {"id": "s9-3-f", "num": "§9.3.f", "name": "Tri-Inspectorate Oversight of Advisory Council", "text": "All three Inspectorates certify the draw under §9.3.d, oversee the Council's working sessions to verify that the Council has the access to records, systems, and personnel required by its statutory mandate, and review the Council's findings before publication to confirm the findings reflect the Counc"}, {"id": "s9-3-g", "num": "§9.3.g", "name": "Advisory Council Findings and Commission Response", "text": "Advisory Council findings are published directly and jointly to the NRS by all three Inspectorates upon completion of the decennial review. Findings may include assessments of cryptographic integrity, node distribution adequacy, technical standard compliance, and any architectural features that appr"}, {"id": "s9-3-h", "num": "§9.3.h", "name": "Senate Public Session on Advisory Council Findings", "text": "Within 30 days of the Advisory Council's findings being published to the NRS under §9.3.g, the Senate must schedule a mandatory public session. The session must occur within 90 days of publication. Advisory Council members appear before the Senate, present their findings, and respond to questions fr"}, {"id": "s9-4", "num": "§9.4", "name": "NRS and Electoral Integrity", "text": "All electoral records (voter registration, ballot counts, audit trails, certification documents) must be published to the NRS within the timeframes specified by the Electoral Commission's constitutional mandate under Article XVI. No classification exception applies to electoral records."}, {"id": "s9-5-b", "num": "§9.5.b", "name": "NRS Downtime Protocol", "text": "In the event of a technical outage, government acts that would otherwise have required NRS publication to take effect are delayed until the outage is resolved. Emergency acts required for immediate public safety may be announced through alternative channels, but the NRS publication requirement appli"}, {"id": "s9-5-c", "num": "§9.5.c", "name": "Citizen NRS Submissions", "text": "Citizens may submit corrections, context, or additional documentation relating to any NRS record via a public submission mechanism maintained by the LI. Submissions are published alongside the original record after accuracy review. Citizens cannot alter government records — only add publicly visible"}, {"id": "s9-5-d", "num": "§9.5.d", "name": "NRS Funding Floor", "text": "Funding for the NRS may not be reduced below the prior year's level without a 2/3 vote of both chambers. The Legislature may increase NRS funding by simple majority. The funding floor protects the NRS from being defunded as a mechanism of opacity — reducing NRS functionality is treated as a constitu"}, {"id": "s9-5-e", "num": "§9.5.e", "name": "Improper Classification", "text": "Classification used to conceal a constitutional violation, an illegal order, or embarrassing but non-sensitive information is constitutionally prohibited in itself. Improper classification is not an administrative error — it is a constitutional offense."}, {"id": "s10-1", "num": "§10.1", "name": "The Social State", "text": "The Republic is a social state. Every Inhabitant is entitled to conditions of life consistent with human dignity. The Republic shall maintain universally accessible healthcare insurance and social assistance systems and shall ensure free compulsory education for all children, as established in §10.1"}, {"id": "s10-1-a", "num": "§10.1.a", "name": "Universal Healthcare Insurance", "text": "The Republic shall maintain a universal healthcare insurance system providing every Inhabitant with access to essential medical care, preventive services, and necessary medications. The system is funded by mandatory employer, employee, and federal government contributions at rates defined by statute"}, {"id": "s10-1-b", "num": "§10.1.b", "name": "Social Assistance", "text": "Where an Inhabitant cannot access the healthcare insurance system, employment income, or other means of support, the Republic provides social assistance sufficient to maintain conditions of life consistent with the §10.1 dignity standard. Eligibility, benefit levels, and delivery mechanisms are defi"}, {"id": "s10-1-c", "num": "§10.1.c", "name": "Compulsory Education", "text": "Every child in the Republic is entitled to free compulsory basic education. States deliver basic education within their territories and may establish standards above the constitutional floor. The constitutional floor requires: literacy and numeracy sufficient for full adult participation in economic"}, {"id": "s10-1-d", "num": "§10.1.d", "name": "Non-Discrimination in Social Systems", "text": "Access to the healthcare insurance system, social assistance, and compulsory education may not be conditioned on citizenship, residency status, political affiliation, or any characteristic protected under §1.9. Every Inhabitant is entitled to equal access. No statute may create tiered access or diff"}, {"id": "s10-1-e", "num": "§10.1.e", "name": "Emergency Protection and Revenue Contraction", "text": "No domestic emergency may reduce, suspend, or diminish access to healthcare insurance, social assistance, or compulsory education. These social state obligations are explicitly excluded from emergency powers; an executive who redirects social insurance or assistance funds during an emergency has com"}, {"id": "s10-2", "num": "§10.2", "name": "Fiscal Accountability Framework", "text": "The constitutional framework for government spending discipline. The Legislature must pass a balanced budget or publish a structural deficit justification. The fiscal framework is enforced by the Inspectorates — the LI audits legislative fiscal claims, the EI audits executive spending certifications"}, {"id": "s10-2-a", "num": "§10.2.a", "name": "Deficit Threshold", "text": "Structural deficits above the constitutional threshold (defined by the MA by statute) require a published justification from the Legislature and a published plan for return to balance. The MA reviews the justification for fiscal accuracy — not political adequacy."}, {"id": "s10-2-b", "num": "§10.2.b", "name": "Legislative Pay Withholding", "text": "Where discretionary government spending has been suspended due to budget failure, the pay of all members of both chambers is withheld from the same date on which government employee pay is withheld — no earlier and no later. Withheld legislator pay is held and released in full within 14 days of a bu"}, {"id": "s10-2-c", "num": "§10.2.c", "name": "National Endowment", "text": "The National Endowment reserve fund for social state backstop purposes under §10.1.e is established and governed under §10.6. The Legislature must fund it by appropriation in years of fiscal surplus. Failure to establish or adequately fund the Endowment within the constitutionally required period is"}, {"id": "s10-3", "num": "§10.3", "name": "Public Campaign Financing", "text": "The Legislature must by statute establish a public campaign financing system within 24 months of the first Legislature convening under §19.3.d. If it fails to do so, the failure is a constitutional compliance breach certified by the LI, and citizens may petition for a citizen legislative initiative "}, {"id": "s10-3-a", "num": "§10.3.a", "name": "Campaign Financing Standards", "text": "The public financing system must provide all registered candidates with equal access to public funds. No incumbent advantage in the allocation formula. Private contributions are capped at the de minimis threshold under §18.3. Administered by the Electoral Commission — not by either executive or the "}, {"id": "s10-3-b", "num": "§10.3.b", "name": "Campaign Financing Enforcement", "text": "Violations are a constitutional breach reportable by the EI. The EI audits all campaign finance records within 90 days of any election. Candidates who received impermissible contributions must refund them or have the amount treated as an undisclosed in-kind contribution."}, {"id": "s10-4", "num": "§10.4", "name": "The Monetary Authority", "text": "The Monetary Authority is the Republic's constitutionally independent central bank, governed by an elected Director and an appointed board. Its mandate hierarchy and independence from political direction are established in this section."}, {"id": "s10-4-a", "num": "§10.4.a", "name": "MA Director Election and Board Composition", "text": "The MA is governed by an elected Director and a board of five appointed members. The Director is elected by national RCV on National Election Day to a single non-renewable 8-year term, staggered from the board member appointment cycle. Board members are appointed by the PM and confirmed by the Senat"}, {"id": "s10-4-b", "num": "§10.4.b", "name": "MA Independence", "text": "The MA's hierarchical mandate is constitutionally fixed: primary mandate is price stability and fiscal solvency; secondary mandate is regard for employment conditions and sustainable growth. The primary mandate takes precedence in all cases of conflict. This hierarchy cannot be altered by ordinary s"}, {"id": "s10-4-b-i", "num": "§10.4.b.i", "name": "Executive Non-Interference", "text": "The Monetary Authority's operational independence is explicitly protected against executive direction. Neither executive may direct, modify, delay, or suppress an MA operational capacity certification. An acting MA Director who issues certifications under executive direction or pressure is subject t"}, {"id": "s10-4-b-ii", "num": "§10.4.b.ii", "name": "Acting MA Director", "text": "Where the MA Director position is vacant or the Director is incapacitated, the board of five members selects an Acting Director from among themselves by majority vote within 7 days of the vacancy or incapacity being established. The Acting Director holds all Director powers except the veto right und"}, {"id": "s10-4-c", "num": "§10.4.c", "name": "Transparency", "text": "All MA determinations, rate decisions, board votes, dissents, and mandate analyses must be published to the NRS within 48 hours of the board meeting. Board Member dissents are published alongside the majority determination."}, {"id": "s10-4-d", "num": "§10.4.d", "name": "Methodology Integrity", "text": "The MA's calculation methodologies must be published and publicly available. The MA may not change its published methodology without 90 days' notice and a published explanation. Covert methodology changes — changing how the numbers are calculated without telling anyone — are a constitutional breach."}, {"id": "s10-4-e", "num": "§10.4.e", "name": "Uncertifiable Inherited Fiscal Position", "text": "Where the MA cannot certify the incoming government's fiscal position because the inherited data is too incomplete or unreliable, the MA publishes a qualified certification explaining the limitations. The Legislature must respond within 30 days with a plan to establish reliable fiscal data."}, {"id": "s10-4-f", "num": "§10.4.f", "name": "Director-Board Authority", "text": "The MA Director chairs the board and holds veto authority over board decisions. The board of five members decides by majority vote; the Director does not hold a board vote. The Director may veto any board decision by publishing written grounds to the NRS within the period the Legislature defines by "}, {"id": "s10-4-g", "num": "§10.4.g", "name": "MA Director Removal", "text": "The MA Director may be removed for cause only. For-cause removal requires: a JI-documented finding transmitted to a State Designee Panel under §8.9.f; a Panel determination that stated grounds are substantiated; a 14-day SC appeal window from publication of the Panel finding; and a 2/3 vote of both "}, {"id": "s10-5", "num": "§10.5", "name": "Ethics and Conflict of Interest", "text": "All constitutional officers are subject to the ethics obligations of this section from the moment they take office. These obligations run concurrently with and do not replace any statutory ethics requirements the Legislature may establish."}, {"id": "s10-5-a", "num": "§10.5.a", "name": "Personal Financial Disclosure", "text": "All elected and appointed constitutional officers must disclose all financial interests, holdings, income sources, and liabilities to the EI within 30 days of taking office and annually thereafter. Disclosure records are published to the NRS. The standard for all official benefits, allowances, and i"}, {"id": "s10-5-b", "num": "§10.5.b", "name": "Conflict of Interest Recusal", "text": "Any constitutional officer with a direct financial interest in a decision within their authority must recuse themselves from that decision. Recusal is self-executing — the officer cannot be excused from recusal by the PM, President, or Legislature. Failure to recuse when required is a constitutional"}, {"id": "s10-5-c", "num": "§10.5.c", "name": "Post-Service and Revolving Door Restrictions", "text": "Constitutional officers may not, for 5 years after leaving office, engage in any activity that monetizes, exploits, or draws on non-public information, relationships, or access accumulated during service. This covers lobbying, consulting, advisory roles, and employment in regulated industries direct"}, {"id": "s10-5-d", "num": "§10.5.d", "name": "Gift and Hospitality Rules", "text": "Constitutional officers may not accept gifts or hospitality above a de minimis threshold defined by statute. All gifts above the threshold must be disclosed to the EI within 30 days and deposited with the relevant treasury. Retention without disclosure is a constitutional breach. Foreign gifts are s"}, {"id": "s10-5-e", "num": "§10.5.e", "name": "Official Records Belong to the Republic", "text": "All records created in the exercise of official functions are public records. Constitutional officers may not retain, destroy, or remove official records after leaving office. Records physically retained without authorization are subject to forfeiture."}, {"id": "s10-5-g", "num": "§10.5.g", "name": "Official Intellectual Property", "text": "Ideas, analyses, and work product created during official service belong to the Republic. An officer may not monetize work done in their official capacity for 5 years following service."}, {"id": "s10-5-h", "num": "§10.5.h", "name": "Ethics Enforcement", "text": "The EI is the primary enforcement mechanism for the §10.5 ethics provisions. The EI publishes all disclosed conflicts, all flagged violations, and all referrals to the Legislature for removal proceedings. The EI publishes facts and refers serious violations — it does not impose penalties directly."}, {"id": "s10-6", "num": "§10.6", "name": "National Endowment", "text": "The National Endowment is a constitutionally established reserve fund that backstops the Republic's social state obligations under §10.1.e during periods of Severe Revenue Contraction. It operates independently of the annual budget process. The Endowment's dual mandate is: (1) maintaining the solven"}, {"id": "s10-6-a", "num": "§10.6.a", "name": "National Endowment Trustee Pool", "text": "The National Endowment is governed by a board of five trustees selected by public lottery from a constitutionally maintained Trustee Pool. The President and PM each nominate one qualified person per year to the Trustee Pool. Each nominee must hold demonstrable expertise in investment management, pub"}, {"id": "s10-6-a-i", "num": "§10.6.a.i", "name": "Trustee Draw and Terms", "text": "When the Endowment board has a vacancy, all three Inspectorates jointly conduct a public lottery draw from the confirmed Trustee Pool, excluding current serving trustees. The draw selects one trustee per vacancy. Trustees serve staggered 6-year non-renewable terms. A trustee drawn to fill a mid-term"}, {"id": "s10-6-a-ii", "num": "§10.6.a.ii", "name": "Trustee Mandate and Accountability", "text": "The board's sole mandate is to preserve and grow the Endowment fund for social state backstop purposes under §10.1.e. The board may not be directed to any other investment goal by either executive or the Legislature. All board decisions, investment mandates, and performance reports are published to "}, {"id": "s10-6-b", "num": "§10.6.b", "name": "National Endowment Activation", "text": "When the MA certifies a Severe Revenue Contraction, the Endowment is automatically activated under §10.1.e. The board must begin disbursements within 30 days: to the healthcare insurance system where its contribution revenues are insufficient to meet its obligations; and to social assistance where a"}, {"id": "s10-7", "num": "§10.7", "name": "Compensation of Public Officials", "text": "No government official may set their own compensation or the compensation of their direct supervisors. All official compensation is set by House statute and is public record on the NRS."}, {"id": "s11-1", "num": "§11.1", "name": "Optional Referendum", "text": "Citizens may initiate a national referendum to repeal enacted legislation by petition of 5% of eligible voters within 90 days of enactment. The LI screens petitions for eligibility — laws that solely or primarily expand an Article I right are not eligible for referendum (the Bill of Rights cannot be"}, {"id": "s11-1-a", "num": "§11.1.a", "name": "Citizen Petition Right", "text": "The 5% petition must be collected within 90 days of the law's enactment. The EC verifies petition signatures for eligibility. If the threshold is met, the EC administers the referendum within 90 days of verification. Petitioners may withdraw the petition before the referendum is scheduled, but not a"}, {"id": "s11-1-b", "num": "§11.1.b", "name": "Eligibility Screen", "text": "The Legislative Inspectorate determines whether a targeted law is eligible for referendum. Laws that solely or primarily expand an Article I right are ineligible; a law cannot be repealed by referendum if its primary effect is to broaden individual protections. Budget laws and laws implementing a co"}, {"id": "s11-1-c", "num": "§11.1.c", "name": "Referendum Thresholds and Finality", "text": "If the referendum passes (simple majority of votes cast, subject to the Legislature-defined turnout threshold), the law is repealed immediately upon EC certification. If it fails, the law remains in effect and cannot be subjected to referendum on the same grounds for 5 years. The Legislature may re-"}, {"id": "s11-2", "num": "§11.2", "name": "Citizen Legislative Initiative", "text": "Citizens hold the right to propose legislation directly to the Legislature through the initiative mechanism. The initiative is distinct from the referendum — it creates new law rather than repealing enacted law."}, {"id": "s11-2-a", "num": "§11.2.a", "name": "Initiative Process and Thresholds", "text": "10% of eligible voters petition for a specific legislative proposal. The Legislature must vote on the proposal within 90 days. If it fails or is not voted on, the proposal proceeds to a national referendum at the §15.1.c thresholds — citizen-initiated legislation that bypasses the Legislature requir"}, {"id": "s11-3", "num": "§11.3", "name": "Local Government", "text": "Local governments — cities, counties, municipalities, and other subdivisions — receive constitutional recognition as the primary points of contact between citizens and government. They are entitled to reasonable fiscal capacity to carry out their constitutional functions. States may not starve local"}, {"id": "s12-1", "num": "§12.1", "name": "Authorized Purposes for Military Force", "text": "The constitution limits military force to three purposes: border protection and territorial integrity; defense of treaty allies within defined triggering thresholds; and prevention of genocide or civilizational collapse. Three prohibited purposes are equally significant: nation-building, resource ex"}, {"id": "s12-2", "num": "§12.2", "name": "Legislative Declaration of Defense", "text": "The Emergency Defense Allocation is the automatic funding mechanism that activates with a Tier 3 Declaration. The PM certifies funds concurrent with the Legislative Declaration — no Declaration takes effect without PM certification. The allocation covers specific categories of military expenditure d"}, {"id": "s12-2-a", "num": "§12.2.a", "name": "Defense Allocation Categories", "text": "The Declaration must specify which expenditure categories are authorized: operational costs, equipment, personnel, intelligence support, logistics, and post-conflict obligations. Expenditure in uncategorized areas requires a supplementary PM certification. The categorization requirement prevents the"}, {"id": "s12-2-b", "num": "§12.2.b", "name": "Emergency Defense Allocation Renewal", "text": "The Emergency Defense Allocation renews automatically with each 180-day Declaration renewal, subject to PM certification. If the Legislature renews the Declaration but the PM withholds certification, the Declaration is voided — the PM's fiscal certification is an independent constitutional check on "}, {"id": "s12-2-c", "num": "§12.2.c", "name": "Allocation Termination", "text": "When the Tier 3 Declaration expires or is not renewed, all Emergency Defense Allocation expenditure ceases automatically within 48 hours. Ongoing contracts within the certified allocation may continue to wind down for 30 days. New commitments may not be entered after Declaration expiry. The EI monit"}, {"id": "s12-2-d", "num": "§12.2.d", "name": "Oversight of Allocation", "text": "The EI audits Emergency Defense Allocation spending quarterly during any active Tier 3 Declaration and publishes findings to the NRS. The audit covers whether expenditure falls within certified categories, whether PM certifications were obtained, and whether expenditure complied with emergency procu"}, {"id": "s12-2-e", "num": "§12.2.e", "name": "Post-Allocation Accountability", "text": "Within 180 days of a Declaration's final expiry, the EI publishes a comprehensive allocation accountability report covering the entire period: total expenditure by category, compliance with PM certifications, and any identified irregularities."}, {"id": "s12-3", "num": "§12.3", "name": "Military Intelligence Operations", "text": "The use of intelligence capabilities in support of authorized military operations. The §1.30.d Intelligence Firewall applies at all times — no military operation authorizes domestic intelligence collection against citizens. Intelligence activities must be published to the NRS in classified summary f"}, {"id": "s12-4", "num": "§12.4", "name": "Military Accountability", "text": "Within 90 days of a Tier 3 Declaration being renewed for a second time, the Senate must approve a Transition and Reconstruction Plan specifying the Republic's post-conflict obligations: status of alliance obligations, civilian reconstruction support, transitional justice support, and withdrawal time"}, {"id": "s12-4-a", "num": "§12.4.a", "name": "Provisional PM Authorization — Transition Plan Failure", "text": "Where the LI has certified a compliance breach under §12.4, the PM may provisionally authorize continued military operations under the existing Declaration using their fiscal certification authority under §2.1.d. Provisional authorization is granted in two extensions of 30 days each — 60 days total "}, {"id": "s12-5", "num": "§12.5", "name": "Treaty-Based Military Authorization", "text": "Where an existing treaty requires emergency military action, the President may invoke Treaty Emergency Certification as an alternative to the standard Tier authorization process, subject to the requirements of §12.5.a and §12.5.b. Treaty Emergency Certification does not displace the Legislature's ul"}, {"id": "s12-5-a", "num": "§12.5.a", "name": "Treaty Emergency Certification", "text": "Where an existing treaty requires emergency military action, the President may invoke Treaty Emergency Certification as an alternative to the standard Tier authorization process. The certification must be published to the NRS within 6 hours with the specific treaty obligation cited. The Senate Armed"}, {"id": "s12-5-b", "num": "§12.5.b", "name": "Treaty Emergency Procedures", "text": "Treaty Emergency Certification activates the same 96-hour Senate Armed Services Committee review as Tier 2 authorization. The President must notify both chambers and the PM within 12 hours of invoking certification, specifying the treaty obligation triggered and the anticipated scope of operations. "}, {"id": "s12-5-c", "num": "§12.5.c", "name": "No Blank Check", "text": "The Treaty Emergency Certification covers operational costs for the initial response and triggers parliamentary authorization for any extended engagement. Treaties cannot be blank checks for extended military commitment — each sustained engagement requires parliamentary authorization regardless of w"}, {"id": "s13-1", "num": "§13.1", "name": "Territorial Compact", "text": "The foundational category for non-State jurisdictions within the Republic. A Territory operates under a Territorial Compact, has federal protections under Article I, accesses social state systems under §10.1, and may begin the Statehood pathway under §13.2. Territories hold House seats proportional "}, {"id": "s13-2", "num": "§13.2", "name": "The Statehood Audit", "text": "The pathway from Territory to State is automatic upon successfully completing the Statehood Audit and Provisional Membership Period. No political vote is required once the audit is passed — statehood is a constitutional entitlement for any Territory that meets the criteria, not a political grant. Th"}, {"id": "s13-2-c", "num": "§13.2.c", "name": "The Provisional Membership Period", "text": "Upon passing the Statehood Audit, the Territory enters a Provisional Membership Period of between one and three years, as the Legislature defines by statute. Clean completion results in automatic Statehood — no further action required."}, {"id": "s13-2-d", "num": "§13.2.d", "name": "Partial Territory Statehood", "text": "A defined geographic subdivision of a Territory may petition for Statehood independently of the remainder. The petitioning subdivision must meet the same Statehood criteria as a whole Territory. Used where a Territory contains a region with clearly different institutional development."}, {"id": "s13-2-e", "num": "§13.2.e", "name": "Minimum Democratic Legitimacy", "text": "Every State must maintain three ongoing conditions: functioning electoral processes under Article XVI, basic rule of law and judicial function, and Article I rights compliance. Annual Statehood Audit verifies continued compliance. A State that fails receives Early Warning under §13.3 — it enters a r"}, {"id": "s13-2-f", "num": "§13.2.f", "name": "Territorial Minimum Institutional Floor", "text": "Every Territory must maintain: a governance council with defined membership and published authority; basic public financial reporting; and access to federal court jurisdiction for Article I claims. Territories that cannot maintain this floor may be placed in federal receivership pending institutiona"}, {"id": "s13-2-g", "num": "§13.2.g", "name": "Conflict-Affected State Provisional Status", "text": "Where active conflict prevents completion of the annual Statehood Audit in a significant portion of a State's territory, the LI may — upon joint certification by all three Inspectorates — grant provisional audit status for that cycle, preserving the State's constitutional standing and social state p"}, {"id": "s13-3", "num": "§13.3", "name": "Mandatory Devolution", "text": "A State enters Mandatory Devolution if it fails three consecutive annual Statehood Audits, certified by the LI and confirmed by both the EI and JI. After each failing audit, the LI publishes an Early Warning specifying compliance requirements; the State must publish a Remediation Plan within 60 days"}, {"id": "s13-3-e", "num": "§13.3.e", "name": "Constitutional Challenge to Devolution", "text": "Within 30 days of a Senate Devolution vote, the affected State may petition the SC on the sole ground that the LI's published audit findings are factually insufficient to establish three consecutive failures under §13.3. The Court reviews only the factual basis of the audit findings — not the Senate"}, {"id": "s13-4", "num": "§13.4", "name": "Voluntary Devolution", "text": "A State may voluntarily restructure its relationship with the Republic. The process requires: a State referendum achieving 60% approval of eligible voters on the specific proposed restructuring (subdivision, merger, Territory status, or independence path); and Senate approval of a negotiated restruc"}, {"id": "s13-5", "num": "§13.5", "name": "Re-Qualification Pathway", "text": "A Territory resulting from mandatory or voluntary devolution enters the Statehood re-qualification pathway under §13.2 immediately upon the effective date of devolution. No additional political vote is required to begin the pathway. The Territory's re-qualification proceeds under the same Statehood "}, {"id": "s13-6", "num": "§13.6", "name": "Voluntary Incorporation", "text": "A sovereign entity may petition to join the Republic's constitutional framework as a Territory. The process requires: a petition resolution adopted by the entity's own legislature or assembly by 2/3 majority, confirmed by a citizen referendum achieving simple majority on at least 50% participation; "}, {"id": "s13-7", "num": "§13.7", "name": "Territorial Merger with Existing State", "text": "A Territory, or a defined geographic portion of a Territory, may merge with a geographically contiguous existing State. Merger requires: a referendum of the merging Territory's eligible voters achieving 60% affirmative with at least 50% participation; approval by the existing State through its own c"}, {"id": "s13-8", "num": "§13.8", "name": "State Immutability", "text": "A State's constitutional boundaries are fixed. No constitutional mechanism permits a State to divide directly into two or more States. Where a State seeks to subdivide, it must first voluntarily devolve to Territory status under §13.4 — each resulting Territory then pursues Statehood independently t"}, {"id": "s14-1", "num": "§14.1", "name": "Acknowledgment of Prior Sovereignty", "text": "The foundational provision recognizing that Indigenous Nations within the Republic's territory hold a distinct constitutional relationship based on prior sovereignty. The compact relationship is bilateral: the Republic acknowledges Indigenous prior sovereignty; Indigenous Nations acknowledge the Rep"}, {"id": "s14-2", "num": "§14.2", "name": "Compact Formation", "text": "An Indigenous Nation may enter a compact with the Republic by submitting a compact proposal to the Senate. The Senate must within 90 days either begin compact negotiations or publish written reasons for declining; a declined proposal may be resubmitted after 5 years or after a material change in cir"}, {"id": "s14-3", "num": "§14.3", "name": "Rights and Governance in Compact Territories", "text": "Article I rights apply in full within all compact territories. Indigenous Nations with compacts hold governance, judicial, and resource sovereignty within their territories, subject to the specific terms of this section."}, {"id": "s14-3-a", "num": "§14.3.a", "name": "Article I Rights in Compact Territories", "text": "Article I rights apply in full within compact territories. No compact provision may limit or qualify any Article I right. The compact creates a framework for Indigenous governance, not a carve-out from constitutional rights. Where compact governance conflicts with an Article I right, Article I preva"}, {"id": "s14-3-b", "num": "§14.3.b", "name": "Compact Judicial Authority", "text": "Indigenous Nations with compacts may establish their own courts with jurisdiction over matters within compact scope. These courts operate in parallel with federal courts. Citizens may bring Article I claims directly to federal courts regardless of whether a matter is within compact scope."}, {"id": "s14-3-c", "num": "§14.3.c", "name": "Land and Resource Sovereignty", "text": "Compact territories include explicit land and resource sovereignty provisions negotiated between the Nation and the Republic. The Republic may not alter compact land provisions without Nation consent. Resource extraction within compact territories requires both Republic and Nation approval."}, {"id": "s14-3-d", "num": "§14.3.d", "name": "Compact Governance Recognition", "text": "The Republic recognizes the Indigenous Nation's governance structures as legitimate political institutions within compact scope. Federal agencies must coordinate with compact governance bodies. The Republic may not impose federal administrative structures on compact governance without Nation consent"}, {"id": "s14-3-e", "num": "§14.3.e", "name": "Compact Education and Language", "text": "Compacts must include provisions for preservation and transmission of Indigenous languages and cultural practices. The Republic provides federal education funding that supports Indigenous-language instruction within compact territories."}, {"id": "s14-4", "num": "§14.4", "name": "Compact Administration and Continuity", "text": "Compacts are living agreements administered through joint mechanisms. This section governs dispute resolution, review cycles, and the conditions under which a compact may be modified or terminated."}, {"id": "s14-4-a", "num": "§14.4.a", "name": "Compact Dispute Resolution", "text": "Disputes about compact terms are resolved through a Joint Compact Review Council (equal representation of the Nation and the Republic) with appeal to the SC on constitutional questions. The Council's decisions are binding on both parties within the scope of the compact. Neither party may unilaterall"}, {"id": "s14-4-b", "num": "§14.4.b", "name": "Compact Review Cycle", "text": "Compacts are reviewed on a schedule defined in the compact terms, minimum every 20 years. Either party may request a review outside the scheduled cycle. Reviews are conducted by the Joint Compact Review Council. The review may result in compact amendment by mutual agreement — neither party can impos"}, {"id": "s14-4-c", "num": "§14.4.c", "name": "Compact Termination", "text": "A compact may be terminated by mutual agreement only. Neither party may unilaterally terminate a compact. If the Nation seeks termination, the Republic must negotiate exit terms within 2 years. If no agreement is reached, the compact continues and the dispute is referred to the SC. The Republic hold"}, {"id": "s14-5", "num": "§14.5", "name": "Federal Obligations and New Compact Petitions", "text": "The Republic holds affirmative obligations to compact territories. Indigenous communities that do not currently hold a compact retain the right to petition for compact recognition under this section."}, {"id": "s14-5-a", "num": "§14.5.a", "name": "Emergency Rights Writ", "text": "Any resident of compact territory who believes an Article I right has been violated may bring an Emergency Rights Writ directly to the SC, bypassing all lower courts and the compact dispute resolution process. The SC must respond within 7 days. Cannot be displaced by compact terms — a direct constit"}, {"id": "s14-5-b", "num": "§14.5.b", "name": "Federal Assistance Obligations", "text": "The Republic maintains specific assistance obligations to compact nations: federal education funding, healthcare access, infrastructure investment, and emergency response. These obligations are enforceable against the Republic by the Nation through the compact dispute resolution process."}, {"id": "s14-5-c", "num": "§14.5.c", "name": "New Indigenous Compact Petitions", "text": "Indigenous communities that do not currently hold a compact may petition the Senate for compact recognition. The Senate must consider the petition within 90 days and either begin compact negotiations or publish written reasons for declining. A declined petition may be re-submitted after 5 years or a"}, {"id": "s14-5-d", "num": "§14.5.d", "name": "Compact and Citizenship", "text": "Indigenous Nation membership and Republic citizenship are compatible and independent statuses. A citizen of a compact Nation holds full Republic citizenship rights. Republic citizenship does not require renouncing Indigenous Nation membership. Dual status is the constitutional default."}, {"id": "s14-6", "num": "§14.6", "name": "Treaty Supremacy and Continuity", "text": "All treaties entered into by predecessor governments with indigenous nations are binding obligations of the Republic. Treaty rights cannot be diminished by legislation — they must be honored, renegotiated with consent, or formally superseded by mutual agreement through the compact negotiation proces"}, {"id": "s14-7", "num": "§14.7", "name": "Indigenous Nation Status Elections", "text": "An indigenous nation with an established compact under Article XIV holds the constitutional right to initiate a status transition through its own democratic or traditional governance process. Three status options are available: (a) Compact Status — continued Article XIV compact relationship (default"}, {"id": "s14-7-a", "num": "§14.7.a", "name": "Status Election Process", "text": "A status election under §14.7 requires: (1) a decision by the nation's own governance process, meeting the standards the nation itself defines for major governance decisions; and (2) publication of the election to the NRS within 30 days of the governance decision. A status election under §14.7 is ir"}, {"id": "s15-1", "num": "§15.1", "name": "Three Amendment Paths", "text": "The constitution can be amended through three routes with varying levels of democratic mandate. Path A (Legislature only): 3/4 of both chambers simultaneously. Path B (Legislature + popular vote): 2/3 of both chambers + 55% affirmative with 55% participation. Path C (citizens alone): 70% affirmative"}, {"id": "s15-1-a", "num": "§15.1.a", "name": "Parliamentary Path", "text": "Requires 3/4 supermajority of the full seated membership of both chambers in a single concurrent vote. No popular referendum. No executive signature. Every member's vote is published to the NRS within 24 hours. The 3/4 threshold is the highest legislative supermajority in the constitution — near-una"}, {"id": "s15-1-b", "num": "§15.1.b", "name": "Parliamentary and Popular Path", "text": "Lower legislative threshold (2/3 both chambers) but requires the People to ratify. National popular vote within 180 days of the parliamentary vote. 55% affirmative support with at least 55% citizen participation required. EC and LI certify jointly. Neither stage alone is sufficient."}, {"id": "s15-1-c", "num": "§15.1.c", "name": "Citizen-Led Path", "text": "Citizen-Led Amendment. The only path that entirely bypasses the Legislature. 70% affirmative support with 65% citizen participation required. A vote that fails either threshold fails; no second vote is available. A new petition may be filed immediately under the same process, with the failed vote's "}, {"id": "s15-2", "num": "§15.2", "name": "No Executive Veto Over Amendments", "text": "Neither the President nor the PM has any role in the constitutional amendment process. No signature required. No veto available. An amendment takes effect the moment the Inspectorates certify ratification and publish it to the NRS. Constitutional change is entirely outside executive control."}, {"id": "s15-2-a", "num": "§15.2.a", "name": "Amendment Takes Effect", "text": "An amendment takes effect immediately upon LI certification (Paths A and B) or EC certification (Path C) and NRS publication. No implementation delay, no commencement date, no executive discretion over timing."}, {"id": "s15-3", "num": "§15.3", "name": "Unamendable Provisions", "text": "Six provisions of this constitution may not be amended by any pathway — not by legislative supermajority, popular ratification, or any combination of both. These provisions define the minimum conditions for constitutional legitimacy itself."}, {"id": "s15-3-a", "num": "§15.3.a", "name": "Permanently Unamendable Provisions", "text": "Six provisions that cannot be amended by any process: §1.3 (torture prohibition), §1.4 (slavery and forced labor), §1.14 (habeas corpus), §1.18 (public trial), §1.19 (no retroactive criminal laws), §1.28 (non-refoulement). Article I as a whole can only expand — no amendment may reduce any Article I "}, {"id": "s15-4", "num": "§15.4", "name": "Territorial Integrity", "text": "The Republic's territorial extent may only be reduced by the consent of the affected population. No State may leave the Republic through ordinary legislation, and no government may cede territory without meeting the threshold established in this section."}, {"id": "s15-4-a", "num": "§15.4.a", "name": "Amendment Requirement for Territorial Reduction", "text": "The Republic's territorial extent may only be reduced by a Path B or Path C amendment (not Path A). Expansion of territory is governed by §13.1. No executive action may alter the Republic's territorial extent."}, {"id": "s15-4-b", "num": "§15.4.b", "name": "No Secession by Ordinary Legislation", "text": "A State may not secede from the Republic by ordinary statute or by State referendum alone. Secession requires a constitutional amendment — Path B or C — meaning a national democratic majority must consent to the departure of any State."}, {"id": "s15-5", "num": "§15.5", "name": "Amendment Consistency Requirement", "text": "An amendment that is logically inconsistent with an existing provision must either explicitly repeal the inconsistent provision or the inconsistency is treated as void. The LI reviews all proposed amendments for internal consistency before ratification."}, {"id": "s15-5-a", "num": "§15.5.a", "name": "LI Consistency Review", "text": "The LI publishes a consistency analysis of any proposed amendment within 30 days of its official proposal. Identifies provisions the amendment would supersede, modify, or conflict with. Advisory — it does not block ratification — but creates a permanent public record of what the amendment changes."}, {"id": "s15-5-b", "num": "§15.5.b", "name": "SC Consistency Adjudication", "text": "If a ratified amendment's consistency with existing provisions is disputed, the SC resolves the dispute on expedited review. The SC may not refuse to ratify an amendment that has met its procedural thresholds — it adjudicates the consistency question after ratification, not before."}, {"id": "s15-5-c", "num": "§15.5.c", "name": "Retroactive Effect of Amendments", "text": "Amendments take prospective effect from the date of ratification. They do not retroactively alter the constitutionality of acts that were constitutional when performed. Criminal prosecutions and civil proceedings that were constitutionally valid when commenced remain valid under the prior constituti"}, {"id": "s15-5-d", "num": "§15.5.d", "name": "Simultaneous Amendments", "text": "Two amendments may be simultaneously in the ratification process. If both pass, both are law. If they conflict with each other, the one ratified later in time prevails. Where two conflicting amendments are certified on the same day, the amendment with the higher ratification margin prevails; where m"}, {"id": "s15-5-e", "num": "§15.5.e", "name": "Withdrawn Amendments", "text": "A proposed amendment may be withdrawn by the proposing body at any point before ratification is certified. Once ratification is certified, an amendment may only be reversed by a subsequent amendment through one of the three paths."}, {"id": "s15-6", "num": "§15.6", "name": "Supremacy of This Constitution", "text": "This Constitution is the supreme law of the Federated Republic. All legislative acts, executive orders, treaties, administrative decisions, and government actions must be consistent with this Constitution. Any provision inconsistent with this Constitution is void to the extent of the inconsistency."}, {"id": "s16-1", "num": "§16.1", "name": "Digital Infrastructure Commission", "text": "The Digital Infrastructure Commission is a constitutionally independent body responsible for the operation of the National Record System and the National Voting System. It is governed by an elected Director and two panels of three administrators each — the NRS Panel and the Elections Panel. The Comm"}, {"id": "s16-1-a", "num": "§16.1.a", "name": "Director — Election and Term", "text": "The Director is elected by national ranked-choice vote on National Election Day to a single non-renewable 8-year term, staggered from the administrator appointment cycles. The Director chairs the Commission and holds one vote on all Commission decisions. No person may serve more than one term as Dir"}, {"id": "s16-1-b", "num": "§16.1.b", "name": "Panel Composition and Terms", "text": "The NRS Panel consists of three administrators responsible for the operation of the National Record System. The Elections Panel consists of three administrators responsible for the operation of the National Voting System and the administration of all federal elections and referenda. Administrators s"}, {"id": "s16-1-c", "num": "§16.1.c", "name": "Digital Infrastructure Pool and Appointment", "text": "Each executive maintains their own pool of nominees for panel appointments. Either executive may nominate any number of qualified persons to their pool at any time. The JI reviews each nominee and publishes a qualification report to the NRS within 30 days of nomination, assessing whether the nominee"}, {"id": "s16-1-d", "num": "§16.1.d", "name": "Commission Decision-Making", "text": "The full Commission — Director and six administrators — decides on architecture standards, technical policy, budget, and institutional matters by simple majority of full seated membership. The Director holds one vote and is not entitled to a separate veto. For operational decisions within each syste"}, {"id": "s16-1-e", "num": "§16.1.e", "name": "Operational Independence of Panels", "text": "The NRS Panel has sole operational authority over the technical infrastructure, security, cryptographic standards, and system availability of the National Record System. What is published to the NRS is constitutionally determined — the NRS Panel may not withhold, delay, or restrict any record that i"}, {"id": "s16-2", "num": "§16.2", "name": "Administrator Qualifications", "text": "NRS Panel administrators must hold at least 12 years of professional expertise in cryptography, distributed systems, information security, or public records management, and must have no current or recent partisan affiliation. Elections Panel administrators must hold at least 12 years of professional"}, {"id": "s16-2-a", "num": "§16.2.a", "name": "Removal of Director and Administrators", "text": "The Director and panel administrators may be removed for cause only. For-cause removal requires: a JI-documented finding transmitted to a State Designee Panel under §8.9.f; a Panel determination that stated grounds are substantiated; a 14-day SC appeal window from publication of the Panel finding; a"}, {"id": "s16-5", "num": "§16.5", "name": "Digital Infrastructure Commission — Accountability", "text": "The Commission's independence does not place it above accountability. The EI oversees the Director and the Commission as a whole. The LI audits NRS Panel operations and NRS integrity annually under §9.1.e. The JI audits Elections Panel operations and electoral integrity annually. All audit findings "}, {"id": "s16-5-a", "num": "§16.5.a", "name": "Mid-Term Vacancies", "text": "Where a panel administrator seat becomes vacant mid-term, the vacancy process under §16.1.c runs immediately. The replacement serves the remainder of the vacated term only and may not subsequently be nominated to the pool for the same panel track. Where the Director seat becomes vacant, the six pane"}, {"id": "s16-6", "num": "§16.6", "name": "Emergency Technical Authority", "text": "The Legislature must establish by statute a procedure for the Commission to adopt temporary technical measures in imminent security threats or system failures, bypassing the normal majority decision threshold. The emergency power is narrowly constrained — it cannot change electoral rules, timelines,"}, {"id": "s16-3", "num": "§16.3", "name": "NVS Properties", "text": "Three constitutionally required properties of the National Voting System: ballot secrecy (technically impossible to link any vote to any voter), public auditability (aggregate results mathematically verifiable by anyone with NRS access), and resilience (capable of operating in degraded conditions wi"}, {"id": "s16-3-a", "num": "§16.3.a", "name": "Ballot Secrecy", "text": "No person or institution — including Electoral Commission members — may identify how any individual citizen voted. Ballot secrecy is constitutionally absolute. The NVS must make it technically impossible to link any vote to any voter, even in post-election audits."}, {"id": "s16-3-b", "num": "§16.3.b", "name": "Public Auditability", "text": "Every vote cast through the NVS must be individually verifiable by the voter who cast it, without revealing that voter's identity to any other party. The NVS must produce an audit trail that allows independent verification of aggregate results without individual identification. Both requirements mus"}, {"id": "s16-3-c", "num": "§16.3.c", "name": "Resilience and Privacy", "text": "The NVS must operate in degraded conditions without compromising ballot secrecy or auditability. No information generated by the NVS — including voter participation records — may be shared with any government body, law enforcement, or foreign entity for any purpose other than administering the relev"}, {"id": "s16-4", "num": "§16.4", "name": "Voting Rights and Access", "text": "Every citizen holds the right to vote in federal elections. The Electoral Commission administers the Citizen Voting Credential and is constitutionally obligated to maintain access to the National Voting System for every eligible citizen."}, {"id": "s16-4-a", "num": "§16.4.a", "name": "The Citizen Voting Credential", "text": "The Citizen Voting Credential is issued and managed by the Electoral Commission. The system stores only cryptographic identifiers — not names, biometric data, or personal information — ensuring the link between a citizen and their credential cannot be used to identify how they voted. Voluntary biome"}, {"id": "s16-4-b", "num": "§16.4.b", "name": "Remote Voting", "text": "Legislature may by statute authorize authenticated remote voting through the NVS. Remote voting must meet the same cryptographic and auditability standards as in-person NVS voting. No remote voting system may reduce ballot secrecy or auditability below the in-person standard."}, {"id": "s16-4-c", "num": "§16.4.c", "name": "State Voting Method Flexibility", "text": "States may implement early voting periods, mail-in ballot options, and alternative participation methods, provided all methods connect to the NVS and meet its cryptographic and auditability standards. States may not reduce NVS access or capacity as a condition of offering alternative methods."}, {"id": "s16-4-d", "num": "§16.4.d", "name": "Federal Ballot Information", "text": "Before each federal election window opens, the Electoral Commission delivers to every eligible citizen: the list of federal races on their ballot, the NVS access procedures, and the certification timeline. Delivery must reach every eligible citizen through at least two distinct channels."}, {"id": "s16-4-e", "num": "§16.4.e", "name": "State Ballot Information on Request", "text": "At a State's request, the Electoral Commission may extend ballot information delivery to cover State and local races. The State bears the cost. The Commission may not refuse except on operational capacity grounds."}, {"id": "s16-7", "num": "§16.7", "name": "Day Zero Voting System Transition", "text": "Legislature must establish by statute the transition from any predecessor voting infrastructure to the constitutionally required NVS. The statute must ensure continuity of democratic participation — no gap between the predecessor system going offline and the NVS coming online."}, {"id": "s17-1", "num": "§17.1", "name": "The Use Doctrine", "text": "Federal government holds no territorial sovereignty within any State or Territory. All federal property rights are functional use rights — operational control over a designated footprint for the duration of the stated function. Use rights do not constitute ownership, do not transfer sovereignty from"}, {"id": "s17-2", "num": "§17.2", "name": "Seat of Government", "text": "The Republic holds no territorial sovereignty at its Seat of Government. The Seat is hosted by a State or Territory selected through the competitive bid process under this Article. The federal government holds only Operational Use Rights (§17.3) over the designated footprint. The host State or Terri"}, {"id": "s17-2-a", "num": "§17.2.a", "name": "Bid Process and Requirements Specification", "text": "Before issuing a call for bids, the PM publishes a Seat of Government Requirements Specification to the NRS defining the minimum functional, security, physical, and operational requirements any hosting bid must meet; the Legislature establishes by statute the specific standards within those categori"}, {"id": "s17-2-b", "num": "§17.2.b", "name": "Twenty-Year Review Cycle", "text": "Every twenty years from the date the current hosting statute takes effect, the federal government must issue a new call for bids under the §17.2.a process. All States and Territories, including the current host, may submit bids. If no new bids are submitted, the current arrangement continues under t"}, {"id": "s17-2-c", "num": "§17.2.c", "name": "Transition Window", "text": "When the Seat of Government moves to a new host following a bid review, a two-year transition window begins from the date the new hosting statute takes effect. During the transition window, the current host continues as the default temporary Seat. The transition statute must specify the handover tim"}, {"id": "s17-2-d", "num": "§17.2.d", "name": "No-Bid Scenario", "text": "If no State or Territory submits a bid within the call period, the Senate identifies candidate States and Territories that meet the Requirements Specification published under §17.2.a and presents options to the House within 90 days of the close of the bid period. If the Senate fails to present candi"}, {"id": "s17-2-e", "num": "§17.2.e", "name": "Federal Control Within Footprint", "text": "Within the specific registered footprint, the federal government has exclusive operational control. The host State or Territory may not tax federal operations, interfere with federal functions, or apply its own law to federal operations within the footprint."}, {"id": "s17-2-f", "num": "§17.2.f", "name": "Resident Rights", "text": "Persons residing within any area designated as the federal footprint under §17.3 retain full Article I rights enforceable in federal courts. The host State or Territory may not apply residency-based restrictions on federal footprint residents that conflict with Article I."}, {"id": "s17-3", "num": "§17.3", "name": "Operational Use Rights", "text": "The federal government holds property interests within States through Operational Use Rights rather than fee ownership."}, {"id": "s17-3-a", "num": "§17.3.a", "name": "Registration", "text": "Every federal operational use right must be registered on the NRS with precise geographic boundaries, authorized purpose, and termination conditions. There are no unregistered federal land claims. Federal property rights are explicit, bounded, and auditable."}, {"id": "s17-3-b", "num": "§17.3.b", "name": "Termination and Reversion", "text": "When a federal function ends, the Operational Use Right terminates automatically. The federal government must publish notice of termination to the NRS within 30 days. The land and all improvements revert to the host State automatically unless the federal government and host State negotiate a retenti"}, {"id": "s17-3-c", "num": "§17.3.c", "name": "Improvements — Negotiated Settlement", "text": "All improvements on federal Operational Use Rights default to reverting to the host State with the land. The federal government and host State may negotiate a different arrangement within the statutory reversion window. No agreement means automatic reversion at no cost. The burden is on the federal "}, {"id": "s17-3-d", "num": "§17.3.d", "name": "Disputes", "text": "Disputes over use right boundaries, termination, or improvement valuation go to the SC on an expedited track. Neither party may occupy or alter disputed land during pending resolution. The expedited track ensures federal operational continuity — resolution must happen fast enough to maintain the rel"}, {"id": "s17-3-e", "num": "§17.3.e", "name": "Independence Transition", "text": "Where a State achieves independence through a constitutional amendment under §15.4.a and a voluntary devolution agreement under §13.4, automatic reversion under §17.3.b does not immediately apply to Operational Use Rights within the departing territory. Use rights continue under the terms of the fra"}, {"id": "s17-4", "num": "§17.4", "name": "The National Trust", "text": "The National Trust holds all federal land not conveyed by statute to States, indigenous compact territories, or private parties. Land disposal requires statute — the executive cannot convey or encumber public land unilaterally. The National Trust Administrator is independently confirmed under the §2"}, {"id": "s17-4-a", "num": "§17.4.a", "name": "Trust Nature", "text": "National Trust lands are designated as permanent heritage, ecological, or public recreation resources. Trust designation requires a 2/3 vote of both chambers with host State consent. Trust lands are not subject to Operational Use Right termination. The stewardship obligation (§17.4.b) applies from t"}, {"id": "s17-4-b", "num": "§17.4.b", "name": "Stewardship Obligation", "text": "The federal government has an active, enforceable obligation to maintain ecological integrity and public accessibility of National Trust lands. EI monitors stewardship compliance annually, cross-referenced with §1.23 (Right to a Healthy Environment). Failure triggers a mandatory remediation plan rep"}, {"id": "s17-4-c", "num": "§17.4.c", "name": "Co-Management", "text": "States and indigenous nations may enter co-management agreements with the Domestic Affairs Council for National Trust lands within their borders or ancestral territories. Co-management does not transfer Trust ownership or alter the constitutional Trust status. Indigenous nations' participation refle"}, {"id": "s17-4-d", "num": "§17.4.d", "name": "Reclassification Threshold", "text": "Land may be removed from National Trust designation only by a 2/3 vote of both chambers with host State consent, followed by SC review within 60 days. The SC reviews whether the removal complies with any applicable international obligations. Removal is permanent — land removed from Trust does not au"}, {"id": "s17-4-e", "num": "§17.4.e", "name": "International Sites", "text": "National Trust lands recognized under international conservation agreements require a 2/3 Senate vote to withdraw from the relevant international obligation before the national removal process begins. The Republic cannot quietly delist internationally recognized sites without formal democratic actio"}, {"id": "s17-4-f", "num": "§17.4.f", "name": "Admission of New Trust Lands", "text": "Land may be designated National Trust by a 2/3 vote of both chambers with host State consent (land in Territories: 2/3 vote alone). No executive action may designate Trust lands — designation is a legislative act."}, {"id": "s17-4-g", "num": "§17.4.g", "name": "National Trust Administrator", "text": "The National Trust Administrator is a statutory independent officer whose independence is protected by statute. The Legislature creates the office by statute and establishes the Administrator's independence, term, and removal grounds through the enabling statute. The enabling statute may not reduce "}, {"id": "s17-5", "num": "§17.5", "name": "Federal Property in Territories", "text": "Federal operational use rights in Territories follow the same framework as in States under §17.3 and §17.4. Host State legislative consent is not required because Territories have no State legislature; the Territory's representative body and the LI are consulted before any use right is registered. T"}, {"id": "s18-1", "num": "§18.1", "name": "Electoral Finance", "text": "Electoral finance is regulated to prevent the structural distortion of democratic accountability through concentrated financial influence. The provisions of this section govern contributions, disclosure, and independent expenditures."}, {"id": "s18-1-a", "num": "§18.1.a", "name": "Financial Contributions as Electoral Acts", "text": "All contributions above the de minimis threshold must be publicly disclosed to the Electoral Commission and published to the NRS. Anonymity in electoral finance is prohibited. The de minimis threshold may not be set so high that it effectively permits anonymous large-scale contributions."}, {"id": "s18-1-b", "num": "§18.1.b", "name": "Natural Persons Only", "text": "Individual contributions to electoral campaigns are capped at a level defined by statute. Corporate, organizational, and foreign contributions are prohibited. The prohibition on foreign contributions applies to any person or entity that is not a Republic citizen or resident."}, {"id": "s18-1-c", "num": "§18.1.c", "name": "Voter-Donor Parity", "text": "Expenditures made independently of but in support of a campaign must also be disclosed. Independent expenditures are not subject to the same contribution limits as direct contributions, but are subject to the same disclosure requirements. Coordinated expenditures are treated as direct contributions."}, {"id": "s18-1-d", "num": "§18.1.d", "name": "Full Disclosure", "text": "The Electoral Commission administers all electoral finance rules, reviews all disclosed contributions, publishes all disclosures to the NRS, and investigates suspected violations. The EI audits EC administration annually. Candidates who receive impermissible contributions must report them within 10 "}, {"id": "s18-2", "num": "§18.2", "name": "Campaign Conduct", "text": "Candidates for constitutional office are subject to conduct standards administered by the Electoral Commission. These standards govern factual accuracy, media access, and foreign interference — not political content or viewpoint."}, {"id": "s18-2-a", "num": "§18.2.a", "name": "Campaign Conduct Standards", "text": "Candidates for constitutional office must campaign in compliance with published EC conduct standards: prohibition on demonstrably false statements of material fact about a candidate's recorded votes — specifically, claiming a vote was cast when it was not, or was not cast when it was; characterizati"}, {"id": "s18-2-b", "num": "§18.2.b", "name": "Media and Communication Standards", "text": "Campaign communications must clearly identify their sponsor. Fabricated or deceptively edited communications about other candidates are a constitutional violation, not merely a campaign conduct infraction. The EC may require advance disclosure of paid media buys above a threshold defined by statute."}, {"id": "s18-2-c", "num": "§18.2.c", "name": "Foreign Interference Prohibition", "text": "Any attempt by a foreign government, foreign national, or foreign-controlled entity to influence a Republic election is a constitutional violation. The EI investigates and publishes findings. Candidates who knowingly accept foreign assistance — financial or operational — are disqualified from the el"}, {"id": "s18-2-d", "num": "§18.2.d", "name": "Incumbent Advantage Rules", "text": "Constitutional officeholders standing for election in a different race must observe strict separation between their official functions and their campaign. Official resources — staff, communications infrastructure, government platforms — may not be used for campaign purposes. The EI monitors complian"}, {"id": "s18-3", "num": "§18.3", "name": "Public Campaign Financing", "text": "The Republic maintains a publicly funded campaign financing system as an alternative to private fundraising. Participation is voluntary; the system is structured to ensure candidates who participate can mount effective campaigns."}, {"id": "s18-3-a", "num": "§18.3.a", "name": "Public Financing Structure", "text": "Consistent with §10.3.a, the public financing system provides all registered candidates with equal baseline funding. Candidates who accept public financing are subject to spending limits defined by statute. The EC administers disbursement; no allocation may advantage incumbents or established partie"}, {"id": "s18-3-b", "num": "§18.3.b", "name": "Matching Funds", "text": "The Legislature may by statute create a matching funds component providing additional public funds that match small contributions from citizens — amplifying the influence of small donors relative to large ones. Matching thresholds, caps, and ratios are defined by statute and must apply equally to al"}, {"id": "s18-3-c", "num": "§18.3.c", "name": "EC Allocation of Public Funds", "text": "The EC allocates public campaign funds based on objective criteria published before each election cycle. Allocation criteria may include: number of qualifying signatures, prior election performance, demonstrated candidacy viability. No criterion may favor incumbents or penalize first-time candidates"}, {"id": "s18-3-d", "num": "§18.3.d", "name": "Electoral Finance — Not Protected Speech", "text": "Financial contributions to electoral campaigns are not constitutionally protected speech under §1.5, and are not protected as associational activity under §1.8. The regulation of electoral finance is a matter of democratic integrity explicitly reserved from both speech and associational protection."}, {"id": "s19-1", "num": "§19.1", "name": "The Activation Threshold", "text": "This constitution takes effect upon ratification by the required threshold established in §19.1.a. Ratification creates binding constitutional obligations on all governmental actors, existing institutions, and successor entities within the Republic's jurisdiction from Day Zero. The ratification proc"}, {"id": "s19-1-a", "num": "§19.1.a", "name": "Activation Threshold", "text": "Activated upon: (1) interim EC certification that the NVS is operational and meets §16.3; and (2) a national ratification vote achieving 60% affirmative support with at least 50% participation. The NVS certification requirement ensures the system that conducts the ratification vote meets constitutio"}, {"id": "s19-1-b", "num": "§19.1.b", "name": "Institutional Accommodation", "text": "Where the ratifying polity maintains existing institutions overlapping with constitutional mechanisms, the Legislature must by statute within two years of Phase 4 define their relationship with the constitutional framework. Non-diminishment: accommodation statutes may not reduce legal standing of pr"}, {"id": "s19-1-c", "num": "§19.1.c", "name": "Multi-Founder Formation", "text": "Where multiple sovereign nations simultaneously pool sovereignty through a treaty of union, transition provisions adapt: joint Phase 0/1 certification, consolidated debt assumption, combined Day Zero NRS publication of all founding sovereigns' records, and proportional obligation assumption per trea"}, {"id": "s19-2", "num": "§19.2", "name": "Day Zero", "text": "Day Zero is the date the ratification threshold is certified as achieved by the interim EC. Upon ratification: all laws conflicting with the Individual Sovereignty Floor are immediately null and void; all public assets transfer to the NRS; the 24-month Transition Window begins. The Republic exists t"}, {"id": "s19-3", "num": "§19.3", "name": "The Four-Phase Transition", "text": "The constitution is implemented through a 24-month, four-phase transition process established in §19.3.a through §19.3.e."}, {"id": "s19-3-a", "num": "§19.3.a", "name": "Phase 0 — Pre-Ratification Preparation", "text": "Phase 0 is the pre-ratification preparation period. The interim Electoral Commission is constituted, the National Voting System is certified operational, and the joint Inspectorate panel is formed — all before any ratification vote occurs."}, {"id": "s19-3-b", "num": "§19.3.b", "name": "Phase 1 — Emergency Stabilization (Days 1–90)", "text": "Existing government officials serve as caretakers under §19.4. The joint Inspectorate panel assumes oversight. The NRS begins recording all government acts. Priority functions: social state system continuity under §10.1, public safety, and essential services. No new permanent legislation."}, {"id": "s19-3-c", "num": "§19.3.c", "name": "Phase 2 — Institutional Construction (Days 91–270)", "text": "Phase 2 (Days 91–270) is Institutional Construction. Statehood Audits are conducted for all entering territories. Inspectorates are formally constituted. The Candidate Register for MA board members and the NRS Panel administrators of the Digital Infrastructure Commission are appointed. Digital Infra"}, {"id": "s19-3-d", "num": "§19.3.d", "name": "Phase 3 — First Elections (Days 271–450)", "text": "Phase 3 (Days 271-450) is First Elections. The first National Election Day. Supreme Court justices nominated by the PM and confirmed by the Senate under §4.2.d and §4.2.h. Electoral Commission inaugural elections. Phase 3 ends when the first the Legislature is sworn in and the first executives take "}, {"id": "s19-3-e", "num": "§19.3.e", "name": "Phase 4 — Full Constitutional Operation", "text": "Beginning the day the first Legislature convenes and the first executives take the constitutional oath. From Phase 4, all constitutional provisions are fully operative. The 24-month Transition Window concludes at the end of Phase 4."}, {"id": "s19-4", "num": "§19.4", "name": "Caretaker Status", "text": "All existing government officials serve as caretakers during the Transition Window — restricted to maintaining existing services only. No new permanent legislation. Transition supervised by joint Inspectorate panel: one representative per Inspectorate, appointed by their respective IGs. The panel di"}, {"id": "s19-5", "num": "§19.5", "name": "Pre-Constitutional Classified Documents", "text": "Legislature must establish a Classification Review Commission within 90 days of Phase 4 activation. Commission applies §9.5 criteria to predecessor classified material: legitimately classified material enters the §9.5 duration framework from Day Zero; improperly classified material (concealing viola"}, {"id": "s19-6", "num": "§19.6", "name": "Pre-Existing Obligations", "text": "The Republic assumes the public debt obligations of its predecessor government as a constitutional matter, not a discretionary choice."}, {"id": "s19-6-a", "num": "§19.6.a", "name": "Debt Assumption", "text": "The Republic assumes all legally recognized debts of the prior government. The Republic does not inherit a clean slate — it inherits what was borrowed. Selective repudiation of prior obligations is not available as a founding act."}, {"id": "s19-6-b", "num": "§19.6.b", "name": "Active Military Operations", "text": "Active military operations of the prior government continue under existing authorization until the §12.2 Tier framework can apply. The President, once inaugurated, must certify each active operation under the appropriate Tier within 14 days or begin orderly cessation. Operations not certified within"}, {"id": "s19-6-c", "num": "§19.6.c", "name": "Social Insurance Programs", "text": "Retirement pensions, disability benefits, health coverage — of the prior government continue uninterrupted during the Transition Window. The Republic does not create a gap in social protection as part of its founding."}, {"id": "s19-6-d", "num": "§19.6.d", "name": "Veterans and National Service Obligations", "text": "The Republic inherits and honors all benefit obligations to persons who served in military or national service roles under the prior government. These are existing contractual commitments of the sovereign that survive transition as continuity-of-state. Legislature must pass a Veterans and National S"}, {"id": "s19-6-e", "num": "§19.6.e", "name": "Constitutional Claims Court", "text": "The immediate nullification of laws conflicting with the Individual Sovereignty Floor creates constitutional disputes that existing courts may not have capacity to absorb. The Legislature must by statute establish an interim Constitutional Claims Court within Phase 2, with jurisdiction over all Arti"}, {"id": "s19-6-f", "num": "§19.6.f", "name": "Legal Continuity", "text": "The Federated Republic is the legal continuation of the prior government as a matter of international law. All international obligations, financial commitments, treaty relationships, and contractual obligations of the prior government as of Day Zero are assumed by the Republic as its successor sover"}, {"id": "s19-7", "num": "§19.7", "name": "Transition-Period Territory and Subdivision Elections", "text": "The transition period provides specific mechanisms for territories seeking statehood and for prior-government states seeking subdivision. These mechanisms operate alongside the standard Phase structure and do not delay Phase activation."}, {"id": "s19-7-a", "num": "§19.7.a", "name": "Transition-Period Territorial Elections", "text": "Territories or subdivisions meeting the §13.2 Competency Baseline by Phase 2 end may petition to enter as State or Territory. Those failing the Baseline enter as Territory under §13.1 and may begin the Statehood Audit immediately. Any territory may choose Territory status by simple legislative vote "}, {"id": "s19-7-b", "num": "§19.7.b", "name": "Subdivision Elections", "text": "Prior government states or territories may voluntarily subdivide during the Transition Window by vote of their existing legislative body. New subdivisions are treated as separate petitioning entities for §19.7.a purposes. Legislature must establish by statute the subdivision recognition process."}, {"id": "s19-7-c", "num": "§19.7.c", "name": "Phase 2 Statehood Audit Failures", "text": "Where a state fails the Phase 2 Statehood Audit, it enters as a Territory under §13.1 rather than a State. Its population retains all Article I rights. Territory residents from failed-audit states participate in first House elections proportionally. Audit failure does not disenfranchise the populati"}, {"id": "s19-7-d", "num": "§19.7.d", "name": "Pre-Existing Territories and the District", "text": "All prior government territories that have not achieved statehood by Day Zero enter as Territories from Phase 4 activation — without undergoing Phase 2 Statehood Audits, beginning the standard §13.2 Statehood Audit process after Phase 4. Any capital district or special administrative region that was"}, {"id": "s19-8", "num": "§19.8", "name": "Transition Candidate Registers", "text": "The joint Inspectorate panel assembles the initial Candidate Registers for all constitutionally established positions before Phase 3 elections can occur. Without populated registers, the elections cannot proceed — the Registers are a constitutional prerequisite for the democratic machinery to activa"}, {"id": "s19-8-a", "num": "§19.8.a", "name": "Initial Register Assembly", "text": "During Phase 2, the joint Inspectorate panel assembles an initial Candidate Register for the MA board members and NRS Panel administrators. Panel receives disclosure records, reviews factual accuracy, applies constitutional eligibility criteria, and publishes with recommendations to NRS. May draw on"}, {"id": "s19-8-b", "num": "§19.8.b", "name": "Interim Functions and First Nomination", "text": "The joint Inspectorate panel performs interim MA fiscal certification functions from Phase 4 activation until the first MA Director takes office following the Phase 3 election. These interim certifications carry full constitutional weight. The first PM must nominate MA board members within 90 days o"}, {"id": "s19-9", "num": "§19.9", "name": "Transitional Accountability Mechanism", "text": "Where a ratifying polity's predecessor government has documented constitutional violations — systematic rights abuses, documented atrocities — the Republic may establish a Transitional Accountability Mechanism by statute. The TAM is time-limited, non-criminal (it cannot impose criminal sentences), a"}, {"id": "s19-9-a", "num": "§19.9.a", "name": "TAM Establishment and Scope", "text": "The Transitional Accountability Mechanism investigates, documents, and recommends remedies for serious violations committed by predecessor government entities during the period before ratification. Its jurisdiction is bounded to predecessor-era conduct — it does not adjudicate Republic-era acts, whi"}, {"id": "s19-9-b", "num": "§19.9.b", "name": "TAM Amendment and Successor Bar", "text": "The establishing statute and any amendments to it require the same 2/3 majority of both chambers as the original statute. No amendment may expand the Mechanism's subject matter scope beyond the scope defined in the establishing statute."}, {"id": "s19-9-c", "num": "§19.9.c", "name": "TAM Jurisdiction and Publication Limits", "text": "The Mechanism may not exercise criminal jurisdiction — that remains with the courts. The Mechanism may not issue orders whose practical effect is equivalent to criminal punishment, including mandatory prosecution referrals with binding recommendations, civil penalties exceeding the MA-defined thresh"}, {"id": "s19-9-d", "num": "§19.9.d", "name": "TAM Sunset and Rationale", "text": "At sunset the Mechanism dissolves; its NRS record is permanent. The Legislature may not extend the Mechanism beyond its statutory sunset without a fresh 2/3 supermajority in both chambers; extension is not a renewal and does not reset the ten-year successor bar under §19.9.b."}, {"id": "s20-1", "num": "§20.1", "name": "Associated Community Status", "text": "Exclusively for sovereign entities — not a form of State or Territory status, not transitional, not incorporation. Available to nations that have completed the independence process under §15.4.a and §13.4, to independent nations outside the Republic seeking a defined relationship, or to nations reco"}, {"id": "s20-2", "num": "§20.2", "name": "Compact Terms and Equal Sovereignty", "text": "Equal parties; neither constitutionally superior. Observing delegates attend House and Senate proceedings relevant to the compact — speaking rights, no vote, no quorum or threshold effect. The Republic may not impose its constitutional governance architecture on an Associated Community as a conditio"}, {"id": "s20-3", "num": "§20.3", "name": "Compact Conditions and Compliance", "text": "No compact may be entered or ratified with any entity whose governance practices include, authorise, or systematically permit violations of any of the six non-derogable rights established in §1.26.b to any person within its jurisdiction. The Judicial Inspectorate certifies compliance with this condi"}, {"id": "s20-4", "num": "§20.4", "name": "Sovereign Mobility", "text": "The Associated Community may at any time, by its own democratic or traditional governance process, elect to terminate the compact and proceed as a fully independent sovereign nation. No Republic consent is required for compact termination, and the Republic may not impose conditions on or penalties f"}, {"id": "s20-5", "num": "§20.5", "name": "Reciprocal Obligations and Review", "text": "The compact must specify with particularity the reciprocal obligations of both parties and the review mechanism. The Associated Community holds obligations to the Republic as well as rights from it. Review must be scheduled at regular intervals defined in the compact; either party may request a revi"}, {"id": "s20-6", "num": "§20.6", "name": "Compact Ratification", "text": "A compact with an Associated Community requires Senate ratification by 2/3 of full seated membership, consistent with the treaty ratification threshold under §3.2.e. Both executives must transmit the proposed compact to the Senate simultaneously with a joint assessment of its consistency with this A"}, {"id": "s20-7", "num": "§20.7", "name": "Compact Continuity", "text": "Compacts in force at the time of any government transition continue without interruption and bind successive governments of the Republic. No election result, change in the Republic's internal constitutional arrangements, or government transition affects the validity or standing of a compact in force"}];
